import React, { useMemo } from 'react';
import { Question, EvidenceItem } from '../types';
import { CheckCircleIcon, XCircleIcon, LockClosedIcon, TrashIcon } from './icons';
import QuestionExplanationBlocks from './QuestionExplanationBlocks';
import PromptText from './ui/PromptText';
import { sanitizeOptionText } from '../services/questionParser';

interface QuestionViewerProps {
    question: Question;
    selectedOption: string | null;
    isRevealed: boolean;
    onOptionSelect?: (key: string) => void;
    className?: string;
    showMedia?: boolean;
    isLocked?: boolean; 

    eliminatedOptions?: string[];
    onEliminate?: (key: string) => void;
    isEliminationMode?: boolean;
    highlightText?: string;

    // NEW PROP
    evidence?: { stem: EvidenceItem[], options: Record<string, EvidenceItem[]> } | undefined;
}

const QuestionViewer: React.FC<QuestionViewerProps> = ({ 
    question, 
    selectedOption, 
    isRevealed, 
    onOptionSelect, 
    className = "",
    showMedia = true,
    isLocked = false,
    eliminatedOptions = [],
    onEliminate,
    isEliminationMode = false,
    highlightText,
    evidence
}) => {

    const handleOptionClick = (key: string) => {
        if (isLocked) return;

        if (isEliminationMode && onEliminate) {
            onEliminate(key);
            return;
        }

        if (eliminatedOptions.includes(key)) return;

        if (!isRevealed && onOptionSelect) {
            onOptionSelect(key);
        }
    };

    // Detect if this should be rendered as a Gap/Cloze question
    const isGapMode = useMemo(() => {
        if (question.isGapType) return true;
        const text = question.questionText || '';
        // Check for {{...}} or triple underscore patterns
        return /\{\{.+?\}\}|_{3,}/.test(text);
    }, [question]);

    const renderQuestionText = () => {
        // P3 Highlight (Legacy) - Only applies if NOT in gap mode to avoid conflict
        if (!isGapMode && highlightText && question.questionText.includes(highlightText)) {
            const parts = question.questionText.split(highlightText);
            return (
                <span>
                    {parts.map((part, i) => (
                        <React.Fragment key={i}>
                            <PromptText text={part} className="inline" />
                            {i < parts.length - 1 && (
                                <span className="bg-sky-500/30 text-white px-1 rounded animate-pulse font-bold border-b-2 border-sky-500">
                                    {highlightText}
                                </span>
                            )}
                        </React.Fragment>
                    ))}
                </span>
            );
        }

        // Evidence Overlay (New) or Gap Mode
        return (
            <PromptText 
                text={question.questionText} 
                mode={isGapMode ? 'gap' : 'plain'}
                revealExpected={isRevealed}
                highlights={evidence?.stem} 
            />
        );
    };

    return (
        <div className={`space-y-6 pb-10 ${className}`}>
            <div id="question-start-anchor" className="h-px w-full -mt-2"></div>

            {showMedia && (question.questionImage || question.questionAudio) && (
                <div className="flex flex-col gap-4 mb-4">
                    {question.questionImage && <img src={question.questionImage} alt="Questão" className="max-w-full rounded-lg max-h-80 object-contain mx-auto bg-black/20" />}
                    {question.questionAudio && <audio controls src={question.questionAudio} className="w-full" />}
                </div>
            )}

            {/* Question Text */}
            <div className="text-base md:text-lg font-medium leading-relaxed text-slate-200">
                {renderQuestionText()}
            </div>

            <div className="relative">
                {/* LOCKED OVERLAY */}
                {isLocked && (
                    <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-slate-900/10 backdrop-blur-sm rounded-xl border border-white/5 animate-fade-in">
                        <div className="bg-slate-900 p-4 rounded-full shadow-2xl border border-indigo-500/50 mb-3 animate-bounce-subtle">
                            <LockClosedIcon className="w-8 h-8 text-indigo-400" />
                        </div>
                        <p className="text-sm font-bold text-white bg-slate-900/80 px-4 py-2 rounded-lg shadow-lg border border-white/10">
                            Complete o P1 e P2 para liberar
                        </p>
                    </div>
                )}

                {/* ELIMINATION MODE INDICATOR */}
                {isEliminationMode && !isLocked && (
                    <div className="absolute -top-10 left-0 w-full flex justify-center pointer-events-none z-30">
                        <div className="bg-rose-500 text-white px-4 py-1 rounded-full text-xs font-black uppercase tracking-widest shadow-lg animate-pulse flex items-center gap-2">
                            <TrashIcon className="w-3 h-3" /> Modo Eliminação Ativo
                        </div>
                    </div>
                )}

                {/* Options List */}
                <div className={`space-y-2 transition-all duration-500 ${isLocked ? 'opacity-30 filter blur-[3px] pointer-events-none' : 'opacity-100'}`} id="answers-block">
                    {Object.entries(question.options || {}).map(([key, value]) => {
                        if (!value) return null;

                        const displayValue = sanitizeOptionText(value as string);
                        const isEliminated = eliminatedOptions.includes(key);
                        const isSelected = selectedOption === key;
                        const isCorrect = question.correctAnswer === key;
                        const highlights = evidence?.options[key]; // Specific highlights for this option

                        let btnClass = "w-full text-left p-3.5 rounded-xl border-2 transition-all flex gap-3 items-start group ";

                        if (isEliminated) {
                             btnClass += "bg-slate-900/50 border-transparent opacity-40 grayscale decoration-slate-500 line-through cursor-not-allowed";
                        } else if (isRevealed) {
                            if (isCorrect) {
                                btnClass += "bg-emerald-500/20 border-emerald-500 text-emerald-100";
                            } else if (isSelected) {
                                btnClass += "bg-rose-500/20 border-rose-500 text-rose-100";
                            } else {
                                btnClass += "bg-white/5 border-white/5 opacity-50";
                            }
                        } else {
                            if (isEliminationMode) {
                                btnClass += "bg-white/5 border-rose-500/30 hover:bg-rose-500/10 hover:border-rose-500 text-slate-300 cursor-crosshair";
                            } else if (isSelected) {
                                btnClass += "bg-sky-600 border-sky-500 text-white shadow-lg";
                            } else {
                                btnClass += "bg-white/5 border-white/10 hover:border-sky-500/30 hover:bg-white/10 active:scale-[0.99]";
                            }
                        }

                        return (
                            <button
                                key={key}
                                onClick={() => handleOptionClick(key)}
                                disabled={isRevealed || (isLocked)}
                                className={btnClass}
                            >
                                <strong className={`shrink-0 text-base ${!isRevealed && !isSelected && !isEliminated ? 'text-sky-500 group-hover:text-sky-400' : 'text-current'}`}>{key})</strong>
                                <span className="leading-snug pt-0.5 text-sm md:text-base w-full">
                                    <PromptText text={displayValue} highlights={highlights} />
                                </span>
                                {isRevealed && isCorrect && <CheckCircleIcon className="w-5 h-5 ml-auto shrink-0 text-emerald-400" />}
                                {isRevealed && isSelected && !isCorrect && <XCircleIcon className="w-5 h-5 ml-auto shrink-0 text-rose-400" />}
                                {!isRevealed && isEliminated && <TrashIcon className="w-4 h-4 ml-auto shrink-0 text-slate-600" />}
                            </button>
                        );
                    })}
                </div>
            </div>

            {isRevealed && (
                <div className="animate-fade-in pt-6 border-t border-white/10">
                   <QuestionExplanationBlocks 
                        question={question} 
                        userAnswer={selectedOption} 
                        showTitle={true}
                   />
                </div>
            )}
        </div>
    );
};

export default QuestionViewer;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Question, TrapscanEntry, TrapscanSessionConfig } from '../types';
import { useSettings } from '../contexts/SettingsContext';
import * as trapscanLogic from '../services/trapscanLogic';
import { 
    XMarkIcon, LockClosedIcon, ArrowRightIcon, 
    ExclamationTriangleIcon, FullScreenIcon, ExitFullScreenIcon
} from './icons';
import QuestionViewer from './QuestionViewer';
import TrapscanGate from './TrapscanGate';
import QuestionActionsMenu, { QuestionContextType } from './QuestionActionsMenu';
import ReadingContainer from './ui/ReadingContainer';
import { getText } from '../utils/i18nText';
import { isStrictQuestion } from '../services/contentGate';
import ConfirmationModal from './ConfirmationModal';
import { useQuestionDispatch } from '../contexts/QuestionContext';

interface QuestionRunnerProps {
    question: Question;
    sessionConfig?: TrapscanSessionConfig | null;
    onResult: (rating: 'again' | 'hard' | 'good' | 'easy', timeTaken: number, trapscanData?: TrapscanEntry) => void;
    onNext?: () => void;
    isLast?: boolean;
    onClose?: () => void;
    context: QuestionContextType;
    mode?: 'SRS' | 'SIMPLE';
    allowGaps?: boolean;
    onEdit?: (q: Question) => void;
    onDelete?: (id: string) => void;
}

const MediaBlock: React.FC<{ image?: string, audio?: string }> = ({ image, audio }) => {
    if (!image && !audio) return null;
    return (
        <div className="flex flex-col gap-3 items-center mb-6 w-full animate-fade-in" onClick={e => e.stopPropagation()}>
           {image && (
               <img src={image} alt="Mídia da Questão" className="max-w-full max-h-72 rounded-2xl shadow-2xl object-contain bg-black/20" />
           )}
           {audio && (
               <audio controls src={audio} className="w-full max-w-md h-10 opacity-90 hover:opacity-100 transition-opacity" />
           )}
        </div>
    );
};

const QuestionRunner: React.FC<QuestionRunnerProps> = ({ 
    question, 
    sessionConfig, 
    onResult, 
    onNext, 
    isLast, 
    onClose, 
    context,
    mode = 'SRS',
    allowGaps = false,
    onEdit,
    onDelete
}) => {
    const { settings, updateSettings } = useSettings();
    const { deleteQuestions } = useQuestionDispatch();
    const scrollRef = useRef<HTMLDivElement>(null);
    const startTimeRef = useRef<number>(Date.now());

    const isInvalidContent = !allowGaps && !isStrictQuestion(question);

    useEffect(() => {
        if (isInvalidContent) {
            console.warn("[QuestionRunner] Conteúdo inválido detectado. Pulando...", question.id);
            if (onNext) {
                const t = setTimeout(onNext, 100);
                return () => clearTimeout(t);
            }
        }
    }, [question.id, isInvalidContent, onNext]);

    const [isDeleteConfirmOpen, setIsDeleteConfirmOpen] = useState(false);

    if (isInvalidContent) {
        return (
            <div className="flex flex-col items-center justify-center h-full p-10 text-center space-y-4">
                <ExclamationTriangleIcon className="w-12 h-12 text-amber-500 opacity-50" />
                <h3 className="text-xl font-bold text-white">Conteúdo Incompatível</h3>
                <p className="text-slate-400 text-sm">Este item parece ser uma lacuna em modo questão. Pulando...</p>
                <button onClick={onNext} className="bg-white/10 px-6 py-2 rounded-lg text-sm font-bold uppercase hover:bg-white/20">
                    Forçar Pulo
                </button>
            </div>
        );
    }

    // CORRECTION HERE: Explicit type annotation and 'as const' assertions to satisfy TS2345/TS2322
    const activeConfig: TrapscanSessionConfig = useMemo(() => {
        if (sessionConfig) {
            return sessionConfig;
        }

        // Define default object with explicit type literal assertions
        const defaults = { 
            enabled: true, 
            assistMode: true, 
            defaultMode: 'TREINO' as const, 
            lockLevel: 'SOFT' as const
        };

        // Ensure settings.trapscan matches the type if it exists, otherwise fallback
        return (settings.trapscan as TrapscanSessionConfig) || defaults;
    }, [sessionConfig, settings.trapscan]);

    const [selectedOption, setSelectedOption] = useState<string | null>(null);
    const [isRevealed, setIsRevealed] = useState(false);
    const [trapscanData, setTrapscanData] = useState<TrapscanEntry | undefined>(undefined);
    const [showBlockToast, setShowBlockToast] = useState<string | null>(null);

    const [eliminatedOptions, setEliminatedOptions] = useState<string[]>([]);
    const [isEliminationMode, setIsEliminationMode] = useState(false);
    const [highlightAnchor, setHighlightAnchor] = useState(false);

    useEffect(() => {
        setSelectedOption(null);
        setIsRevealed(false);
        setTrapscanData(undefined);
        setEliminatedOptions([]);
        setIsEliminationMode(false);
        setHighlightAnchor(false);
        setIsDeleteConfirmOpen(false);
        startTimeRef.current = Date.now();

        if (scrollRef.current) {
            scrollRef.current.scrollTo({ top: 0, behavior: 'instant' });
        }
    }, [question.id]);

    const isGap = allowGaps && (question.isGapType || question.questionText.includes('{{'));
    const isLocked = !isGap && trapscanLogic.checkAlternativesLocked(activeConfig, trapscanData);
    const blockReason = !isGap ? trapscanLogic.getSubmitBlockReason(activeConfig, trapscanData, !!selectedOption) : null;
    const canSubmit = !blockReason;

    const handleOptionSelect = (key: string) => {
        if (!isRevealed && !isLocked && !isEliminationMode) {
            setSelectedOption(key);
        }
    };

    const handleEliminate = (key: string) => {
        setEliminatedOptions(prev => {
             if (prev.includes(key)) return prev.filter(k => k !== key);
             return [...prev, key];
        });
    };

    const handleReveal = () => {
        if (!canSubmit) {
            setShowBlockToast(blockReason);
            setTimeout(() => setShowBlockToast(null), 3000);
            return;
        }
        setIsRevealed(true);
    };

    const handleRating = (rating: 'again' | 'hard' | 'good' | 'easy') => {
        const timeTaken = (Date.now() - startTimeRef.current) / 1000;
        onResult(rating, timeTaken, trapscanData);
        if (onNext) onNext();
    };

    const handleSimpleNext = () => {
        const isCorrect = selectedOption === question.correctAnswer;
        const timeTaken = (Date.now() - startTimeRef.current) / 1000;
        onResult(isCorrect ? 'good' : 'again', timeTaken, trapscanData);
        if (onNext) onNext();
    };

    const toggleReaderMode = () => {
        const newMode = settings.readerMode === 'compact' ? 'fullscreen' : 'compact';
        updateSettings({ readerMode: newMode });
    };

    const handleDeleteRequest = (id: string) => {
        setIsDeleteConfirmOpen(true);
    };

    const handleConfirmDelete = () => {
        deleteQuestions([question.id]);
        if (onDelete) onDelete(question.id);
        if (onNext) onNext();
        setIsDeleteConfirmOpen(false);
    };

    const showTrapscan = !isGap && trapscanLogic.isTrapscanActive(activeConfig) && !question.isGapType;

    return (
        <div className="flex flex-col h-full bg-[var(--q-surface)] text-[var(--q-text)] relative">
            <header className="px-5 py-4 border-b border-[var(--q-border)] flex justify-between items-center bg-[var(--q-surface)] backdrop-blur-md shrink-0 z-10">
                <div className="min-w-0 pr-4">
                    <h2 className="text-sm font-extrabold tracking-tight truncate uppercase italic">{question.questionRef}</h2>
                    <p className="text-[10px] font-semibold text-[var(--q-muted)] uppercase mt-0.5">{question.subject}</p>
                </div>
                <div className="flex items-center gap-2">
                    {activeConfig?.enabled && showTrapscan && (
                        <div className={`hidden sm:block px-2 py-0.5 rounded text-[9px] font-black uppercase border ${activeConfig.assistMode ? 'bg-indigo-500/10 border-indigo-500/30 text-indigo-400' : 'bg-slate-500/10 border-slate-500/30 text-slate-500'}`}>
                            {activeConfig.assistMode ? (activeConfig.defaultMode === 'GUIA' ? 'GUIA' : `LOCK: ${activeConfig.lockLevel}`) : 'OFF'}
                        </div>
                    )}

                    <button 
                        onClick={toggleReaderMode}
                        className="p-2 rounded-lg text-[var(--q-muted)] hover:bg-[var(--q-hover)] transition-colors hidden sm:block"
                        title={settings.readerMode === 'compact' ? "Expandir Tela" : "Modo Leitura"}
                    >
                        {settings.readerMode === 'compact' ? <FullScreenIcon className="w-5 h-5"/> : <ExitFullScreenIcon className="w-5 h-5"/>}
                    </button>

                    <QuestionActionsMenu 
                        question={question} 
                        context={context} 
                        onEdit={onEdit} 
                        onDelete={handleDeleteRequest} 
                    />

                    {onClose && (
                        <button onClick={onClose} className="p-2 -mr-2 text-[var(--q-muted)] hover:bg-[var(--q-hover)] transition-colors">
                            <XMarkIcon className="w-5 h-5"/>
                        </button>
                    )}
                </div>
            </header>

            <div className="flex-1 overflow-y-auto custom-scrollbar" ref={scrollRef}>
                 <ReadingContainer mode={settings.readerMode} className="py-6 pb-24 md:py-8">
                      <MediaBlock image={question.questionImage} audio={question.questionAudio} />

                      {showTrapscan && !isRevealed && (
                          <TrapscanGate 
                              question={question}
                              isLocked={isLocked}
                              onUnlock={() => {}} 
                              onAllowSubmit={() => {}} 
                              onUpdate={setTrapscanData}
                              userAnswer={selectedOption}
                              configOverride={activeConfig}
                              eliminatedOptions={eliminatedOptions}
                              onSetEliminationMode={setIsEliminationMode}
                              onSetHighlightAnchor={setHighlightAnchor}
                          />
                      )}

                      <QuestionViewer 
                          question={question}
                          selectedOption={selectedOption}
                          isRevealed={isRevealed}
                          onOptionSelect={handleOptionSelect}
                          showMedia={false} 
                          isLocked={isLocked}
                          isEliminationMode={isEliminationMode}
                          eliminatedOptions={eliminatedOptions}
                          onEliminate={handleEliminate}
                          highlightText={highlightAnchor ? getText(question.anchorText) : undefined}
                      />
                  </ReadingContainer>
            </div>

            {showBlockToast && (
                <div className="absolute bottom-24 left-1/2 -translate-x-1/2 bg-rose-500 text-white px-6 py-3 rounded-full shadow-2xl font-bold text-xs uppercase tracking-widest z-50 animate-bounce-subtle flex items-center gap-2">
                    <LockClosedIcon className="w-4 h-4" />
                    {showBlockToast}
                </div>
            )}

            {selectedOption && (
                <footer className="p-5 bg-[var(--q-surface)] border-t border-[var(--q-border)] shrink-0 z-20 pb-[calc(1.5rem+env(safe-area-inset-bottom))] shadow-[0_-10px_40px_rgba(0,0,0,0.3)]">
                    <ReadingContainer mode={settings.readerMode} className="!px-0">
                        {!isRevealed ? (
                            <button 
                                onClick={handleReveal} 
                                disabled={!canSubmit && activeConfig?.assistMode && activeConfig?.defaultMode === 'TREINO'}
                                className={`w-full font-black py-4 rounded-2xl shadow-xl transition-all uppercase tracking-widest text-sm flex items-center justify-center gap-2
                                    ${canSubmit || !activeConfig?.assistMode || activeConfig?.defaultMode === 'GUIA'
                                        ? 'bg-sky-600 text-white hover:bg-sky-500 active:scale-[0.98]' 
                                        : 'bg-slate-700 text-slate-500 cursor-not-allowed opacity-80'}`}
                            >
                                {(canSubmit || !activeConfig?.assistMode || activeConfig?.defaultMode === 'GUIA') ? 'Ver Gabarito' : <><LockClosedIcon className="w-4 h-4"/> Complete o Trapscan</>}
                            </button>
                        ) : (
                            mode === 'SRS' ? (
                                <div className="grid grid-cols-4 gap-3 h-20">
                                    <button onClick={() => handleRating('again')} className="rounded-2xl bg-rose-500/10 border-2 border-rose-500/50 text-rose-500 hover:bg-rose-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Errei</span>
                                    </button>
                                    <button onClick={() => handleRating('hard')} className="rounded-2xl bg-amber-500/10 border-2 border-amber-500/50 text-amber-500 hover:bg-amber-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Difícil</span>
                                    </button>
                                    <button onClick={() => handleRating('good')} className="rounded-2xl bg-sky-500/10 border-2 border-sky-500/50 text-sky-500 hover:bg-sky-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Bom</span>
                                    </button>
                                    <button onClick={() => handleRating('easy')} className="rounded-2xl bg-emerald-500/10 border-2 border-emerald-500/50 text-emerald-500 hover:bg-emerald-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Fácil</span>
                                    </button>
                                </div>
                            ) : (
                                <button 
                                    onClick={handleSimpleNext} 
                                    className={`w-full font-black py-4 rounded-2xl shadow-xl flex items-center justify-center gap-3 uppercase tracking-widest text-xs active:scale-95 transition-all ${isLast ? 'bg-emerald-600 hover:bg-emerald-500 text-white' : 'bg-white text-slate-900 hover:bg-sky-50'}`}
                                >
                                    {isLast ? 'Finalizar' : 'Próxima'} <ArrowRightIcon className="w-4 h-4" />
                                </button>
                            )
                        )}
                    </ReadingContainer>
                </footer>
            )}

            <ConfirmationModal 
                isOpen={isDeleteConfirmOpen} 
                onClose={() => setIsDeleteConfirmOpen(false)} 
                onConfirm={handleConfirmDelete} 
                title="Excluir Questão?"
            >
                <div className="space-y-2">
                    <p className="text-sm text-slate-300">Tem certeza que deseja apagar esta questão? Ela será removida de todas as suas listas de estudo.</p>
                    <p className="text-[10px] font-black text-rose-500 uppercase tracking-widest">Ação irreversível.</p>
                </div>
            </ConfirmationModal>

        </div>
    );
};

export default QuestionRunner;

import React, { createContext, useContext, useState, useEffect, ReactNode, useCallback, useMemo } from 'react';
import { Question, AppSettings, ImportMode } from '../types';
import * as srs from '../services/srsService';
import { SAMPLE_QUESTIONS } from './sample-data';
import { saveData, loadData } from '../services/storage';
import { useSettings } from './SettingsContext';
import { ensureQuestionOptions } from '../services/questionParser';
import { migrateAllQuestions, normalizeQuestion } from '../services/migrationService';
import { traceService } from '../services/traceService';
import { attemptService, AttemptPayload } from '../services/attemptService';
// Removed isStrictQuestion import to allow loading all content types
import { isStrictQuestion } from '../services/contentGate';

const LS_QUESTIONS_KEY = 'revApp_questions_v5_react';

const QuestionStateContext = createContext<Question[] | undefined>(undefined);

interface QuestionDispatch {
  addQuestion: (newQuestion: Omit<Question, 'id'>) => void;
  updateQuestion: (updatedQuestion: Question) => void;
  updateBatchQuestions: (updates: ({ id: string } & Partial<Omit<Question, 'id'>>)[]) => void;
  deleteQuestions: (ids: string[]) => void;
  resetAllProgress: (settings: AppSettings) => void;
  addBatchQuestions: (newQuestions: Omit<Question, 'id'>[], mode?: ImportMode) => { imported: number, blocked: number, updated: number };
  removeDuplicates: () => number;
  registerAttempt: (payload: AttemptPayload) => void;
}

const QuestionDispatchContext = createContext<QuestionDispatch | undefined>(undefined);

export const QuestionProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const { logSystemError, settings } = useSettings();
  const [questions, setQuestions] = useState<Question[]>([]);
  const [isLoaded, setIsLoaded] = useState(false);

  useEffect(() => {
    async function load() {
        try {
            traceService.trace('BOOT_START', 'BOOT');
            const data = await loadData<any[]>(LS_QUESTIONS_KEY);
            let finalQuestions: Question[] = [];

            if (data && Array.isArray(data)) {
                // Apply strict migration but ALLOW Gaps to be loaded
                const rawMigrated = migrateAllQuestions(data);
                finalQuestions = rawMigrated; // Do not filter isStrictQuestion here to allow Trail Gaps

                console.log(`[QuestionContext] Loaded & Migrated ${finalQuestions.length} items.`);
                traceService.trace('BOOT_LOADED', 'BOOT', undefined, { count: finalQuestions.length });
            } else {
                finalQuestions = migrateAllQuestions(SAMPLE_QUESTIONS.map((q, i) => ({...q, id: `q_sample_${i}`})));
            }

            setQuestions(finalQuestions);
            traceService.snapshot('ON_APP_BOOT', { questions: finalQuestions });
        } catch (error) {
            logSystemError(error, 'QuestionContext Load');
            traceService.trace('BOOT_ERROR', 'BOOT', undefined, { error });
        } finally {
            setIsLoaded(true);
        }
    }
    load();
  }, [logSystemError]);

  useEffect(() => {
    if (!isLoaded) return;
    saveData(LS_QUESTIONS_KEY, questions).catch(e => logSystemError(e, 'QuestionContext Save'));
  }, [questions, isLoaded, logSystemError]);

  const addQuestion = useCallback((newQuestionData: Omit<Question, 'id'>) => {
    const normalizedData = normalizeQuestion({ ...newQuestionData, id: 'temp' }, newQuestionData.lawRef || '');
    const { id, ...cleanData } = normalizedData;

    // Warn but allow adding gaps manually if really needed, though usually UI prevents it
    if (!isStrictQuestion(normalizedData as Question) && !newQuestionData.isGapType) {
        console.warn("[QuestionContext] Adding item that doesn't look like a standard question.");
    }

    const fingerprint = srs.generateQuestionFingerprint(cleanData as any);

    setQuestions(prev => {
        if (prev.some(q => q.fingerprint === fingerprint)) {
            console.warn("Duplicate blocked:", cleanData.questionRef);
            return prev;
        }
        const finalId = normalizedData.id && !normalizedData.id.startsWith('temp') 
            ? normalizedData.id 
            : `q_${Date.now()}_${Math.random().toString(36).substring(2, 7)}`;

        traceService.trace('QUESTION_ADD', 'QUESTIONS', finalId, { ref: normalizedData.questionRef });
        return [...prev, { ...cleanData, fingerprint, id: finalId } as Question];
    });
  }, []);

  const addBatchQuestions = useCallback((newQuestions: Omit<Question, 'id'>[], mode: ImportMode = 'SKIP') => {
    let imported = 0;
    let blocked = 0;
    let updated = 0;

    traceService.trace('BATCH_ADD_START', 'QUESTIONS', undefined, { count: newQuestions.length, mode });

    setQuestions(prev => {
        const existingById = new Map<string, Question>(prev.map(q => [q.id, q]));
        const existingByRef = new Map<string, Question>(prev.map(q => [q.questionRef, q]));
        const existingFingerprints = new Set(prev.map(q => q.fingerprint));

        const finalBatch: Question[] = [];
        const updates: Question[] = [];

        newQuestions.forEach((q, idx) => {
            // REMOVED STRICT BLOCK: Allow Gaps to be imported for Trails

            const inputId = (q as any).id;
            const hasStableId = inputId && !inputId.toString().startsWith('temp');
            const normalized = normalizeQuestion({ ...q, id: hasStableId ? inputId : 'temp' }, q.lawRef || '');
            const fingerprint = srs.generateQuestionFingerprint(normalized);

            let existing: Question | undefined;
            if (hasStableId) existing = existingById.get(normalized.id);
            if (!existing) existing = existingByRef.get(normalized.questionRef);

            if (existing) {
                if (mode === 'SKIP') {
                    blocked++;
                } else if (mode === 'MERGE') {
                    const updatedQ = { ...existing };
                    let hasChanges = false;
                    const fieldsToCheck: (keyof Question)[] = [
                        'explanationTech', 'explanationStory', 'feynmanQuestions', 
                        'distractorProfile', 'wrongDiagnosis', 'wrongDiagnosisMap',
                        'rawImportBlock', 'lawRef', 'guiaTrapscan', 'keyDistinction', 'anchorText',
                        'questionText', 'options', 'correctAnswer' // Also update core content on merge for Gaps
                    ];

                    fieldsToCheck.forEach(key => {
                        const val = normalized[key];
                        // If existing is empty OR we are forcing update logic (simplified merge)
                        // For gaps, always update text if provided
                        if ((!updatedQ[key] || (typeof updatedQ[key] === 'object' && Object.keys(updatedQ[key] || {}).length === 0)) && val) {
                            (updatedQ as any)[key] = val;
                            hasChanges = true;
                        }
                    });

                    if (hasChanges) {
                        updates.push(updatedQ);
                        updated++;
                    } else {
                        blocked++;
                    }
                } else if (mode === 'OVERWRITE') {
                    const updatedQ: Question = {
                        ...existing,
                        ...normalized,
                        id: existing.id, 
                        totalAttempts: existing.totalAttempts,
                        masteryScore: existing.masteryScore,
                        stability: existing.stability,
                        nextReviewDate: existing.nextReviewDate,
                        attemptHistory: existing.attemptHistory,
                        lastAttemptDate: existing.lastAttemptDate,
                        lastWasCorrect: existing.lastWasCorrect,
                    };
                    updates.push(updatedQ);
                    updated++;
                }
            } else {
                if (mode === 'SKIP' && existingFingerprints.has(fingerprint)) {
                     blocked++;
                } else {
                    const finalId = normalized.id && !normalized.id.startsWith('temp') 
                        ? normalized.id 
                        : `q_batch_${Date.now()}_${idx}_${Math.random().toString(36).substring(2, 5)}`;

                    finalBatch.push({ ...normalized, fingerprint, id: finalId });
                    existingFingerprints.add(fingerprint);
                    imported++;
                }
            }
        });

        const updatedIds = new Set(updates.map(u => u.id));
        const nextState = prev.map(q => updatedIds.has(q.id) ? updates.find(u => u.id === q.id)! : q);
        const finalState = [...nextState, ...finalBatch];

        return finalState;
    });

    return { imported, blocked, updated };
  }, []);

  const removeDuplicates = useCallback(() => {
      let removedCount = 0;
      setQuestions(prev => {
          const seen = new Set<string>();
          const filtered = prev.filter(q => {
              const fp = q.fingerprint || srs.generateQuestionFingerprint(q);
              if (seen.has(fp)) {
                  removedCount++;
                  return false;
              }
              seen.add(fp);
              return true;
          });
          return filtered;
      });
      return removedCount;
  }, []);

  const updateQuestion = useCallback((updatedQuestion: Question) => {
    const finalQ = normalizeQuestion(updatedQuestion, updatedQuestion.lawRef);
    const canonicalId = srs.getCanonicalId(finalQ.id);

    setQuestions(prev => prev.map(q => {
        if (srs.getCanonicalId(q.id) === canonicalId) {
            return finalQ;
        }
        return q;
    }));
  }, []);

  const updateBatchQuestions = useCallback((updates: ({ id: string } & Partial<Omit<Question, 'id'>>)[]) => {
    setQuestions(prev => {
        const updatesMap = new Map(updates.map(u => [srs.getCanonicalId(u.id), u]));
        return prev.map(q => {
            const update = updatesMap.get(srs.getCanonicalId(q.id));
            return update ? { ...q, ...update } : q;
        });
    });
  }, []);

  const deleteQuestions = useCallback((ids: string[]) => {
    const idsSet = new Set(ids.map(id => srs.getCanonicalId(id)));
    const now = new Date().toISOString();

    traceService.trace('QUESTION_DELETE', 'QUESTIONS', undefined, { count: ids.length, type: 'SOFT_DELETE' });

    setQuestions(prev => prev.map(q => {
        if (idsSet.has(srs.getCanonicalId(q.id))) {
            return { ...q, deletedAt: now };
        }
        return q;
    }));
  }, []);

  const resetAllProgress = useCallback((settings: AppSettings) => {
    setQuestions(prev => prev.map(q => ({
      ...q,
      totalAttempts: 0,
      correctStreak: 0,
      errorCount: 0,
      masteryScore: 0,
      stability: settings.srsV2.S_default_days,
      nextReviewDate: srs.todayISO(),
      lastAttemptDate: '',
      attemptHistory: [],
      masteryHistory: [],
      srsStage: 0,
      lastWasCorrect: false,
      recentError: 0,
      lastReviewedAt: undefined,
    })));
  }, []);

  const registerAttempt = useCallback((payload: AttemptPayload) => {
      const { question, isCorrect, userAnswer, timeSec, trapCode } = payload;

      setQuestions(prev => {
          let targetIndex = prev.findIndex(q => q.id === question.id);
          let targetQ = targetIndex !== -1 ? prev[targetIndex] : question;

          const selfEval = isCorrect ? 3 : 0;
          const srsResult = srs.calculateNewSrsState(targetQ, isCorrect, selfEval, timeSec, settings);

          const updatedQ: Question = {
              ...targetQ,
              ...srsResult,
              yourAnswer: userAnswer,
              totalAttempts: (targetQ.totalAttempts || 0) + 1,
              correctStreak: isCorrect ? (targetQ.correctStreak || 0) + 1 : 0,
              errorCount: !isCorrect ? (targetQ.errorCount || 0) + 1 : targetQ.errorCount,
              lastWasCorrect: isCorrect,
              recentError: !isCorrect ? 1 : 0,
              attemptHistory: [
                  ...(targetQ.attemptHistory || []),
                  {
                      date: srsResult.lastReviewedAt!,
                      wasCorrect: isCorrect,
                      masteryAfter: srsResult.masteryScore!,
                      stabilityAfter: srsResult.stability,
                      timeSec: Math.round(timeSec),
                      selfEvalLevel: selfEval,
                      timingClass: srsResult.timingClass,
                      targetSec: srsResult.targetSec,
                      trapCode
                  }
              ]
          };

          const newState = [...prev];
          if (targetIndex !== -1) {
              newState[targetIndex] = updatedQ;
          } else {
               // Allow upserting any valid item, even Gaps if they come via registerAttempt
               newState.push(updatedQ);
          }

          attemptService.notify(payload);
          return newState;
      });
  }, [settings]);

  const dispatchValue = useMemo(() => ({
    addQuestion, updateQuestion, updateBatchQuestions, deleteQuestions, resetAllProgress, addBatchQuestions, removeDuplicates, registerAttempt
  }), [addQuestion, updateQuestion, updateBatchQuestions, deleteQuestions, resetAllProgress, addBatchQuestions, removeDuplicates, registerAttempt]);

  const visibleQuestions = useMemo(() => questions.filter(q => !q.deletedAt), [questions]);

  return (
    <QuestionStateContext.Provider value={visibleQuestions}>
        <QuestionDispatchContext.Provider value={dispatchValue}>
            {children}
        </QuestionDispatchContext.Provider>
    </QuestionStateContext.Provider>
  );
};

export const useQuestionState = () => {
  const context = useContext(QuestionStateContext);
  if (context === undefined) throw new Error('useQuestionState error');
  return context;
};

export const useQuestionDispatch = () => {
  const context = useContext(QuestionDispatchContext);
  if (context === undefined) throw new Error('useQuestionDispatch error');
  return context;
};

