export default QuestionRunner;

import React, { useMemo } from 'react';
import { Question, EvidenceItem } from '../types';
import { CheckCircleIcon, XCircleIcon, LockClosedIcon, TrashIcon } from './icons';
import QuestionExplanationBlocks from './QuestionExplanationBlocks';
import PromptText from './ui/PromptText';
import { sanitizeOptionText } from '../services/questionParser';

interface QuestionViewerProps {
    question: Question;
    selectedOption: string | null;
    isRevealed: boolean;
    onOptionSelect?: (key: string) => void;
    className?: string;
    showMedia?: boolean;
    isLocked?: boolean; 

    eliminatedOptions?: string[];
    onEliminate?: (key: string) => void;
    isEliminationMode?: boolean;
    highlightText?: string;

    evidence?: { stem: EvidenceItem[], options: Record<string, EvidenceItem[]> } | undefined;
    orderedKeys?: string[]; // SHUFFLE: Array of keys in display order
}

const QuestionViewer: React.FC<QuestionViewerProps> = ({ 
    question, 
    selectedOption, 
    isRevealed, 
    onOptionSelect, 
    className = "",
    showMedia = true,
    isLocked = false,
    eliminatedOptions = [],
    onEliminate,
    isEliminationMode = false,
    highlightText,
    evidence,
    orderedKeys
}) => {

    const handleOptionClick = (key: string) => {
        if (isLocked) return;

        if (isEliminationMode && onEliminate) {
            onEliminate(key);
            return;
        }

        if (eliminatedOptions.includes(key)) return;

        if (!isRevealed && onOptionSelect) {
            onOptionSelect(key);
        }
    };

    // Detect if this should be rendered as a Gap/Cloze question
    const isGapMode = useMemo(() => {
        if (question.isGapType) return true;
        const text = question.questionText || '';
        return /\{\{.+?\}\}|_{3,}/.test(text);
    }, [question]);

    const renderQuestionText = () => {
        if (!isGapMode && highlightText && question.questionText.includes(highlightText)) {
            const parts = question.questionText.split(highlightText);
            return (
                <span>
                    {parts.map((part, i) => (
                        <React.Fragment key={i}>
                            <PromptText text={part} className="inline" />
                            {i < parts.length - 1 && (
                                <span className="bg-sky-500/30 text-white px-1 rounded animate-pulse font-bold border-b-2 border-sky-500">
                                    {highlightText}
                                </span>
                            )}
                        </React.Fragment>
                    ))}
                </span>
            );
        }

        return (
            <PromptText 
                text={question.questionText} 
                mode={isGapMode ? 'gap' : 'plain'}
                revealExpected={isRevealed}
                highlights={evidence?.stem} 
            />
        );
    };

    // Determine list of keys to render
    const keysToRender = useMemo(() => {
        if (orderedKeys && orderedKeys.length > 0) return orderedKeys;
        return Object.keys(question.options || {}).filter(k => !!question.options[k]).sort();
    }, [orderedKeys, question.options]);

    return (
        <div className={`space-y-6 pb-10 ${className}`}>
            <div id="question-start-anchor" className="h-px w-full -mt-2"></div>

            {showMedia && (question.questionImage || question.questionAudio) && (
                <div className="flex flex-col gap-4 mb-4">
                    {question.questionImage && <img src={question.questionImage} alt="Questão" className="max-w-full rounded-lg max-h-80 object-contain mx-auto bg-black/20" />}
                    {question.questionAudio && <audio controls src={question.questionAudio} className="w-full" />}
                </div>
            )}

            {/* Question Text */}
            <div className="text-base md:text-lg font-medium leading-relaxed text-slate-200">
                {renderQuestionText()}
            </div>

            <div className="relative">
                {/* LOCKED OVERLAY */}
                {isLocked && (
                    <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-slate-900/10 backdrop-blur-sm rounded-xl border border-white/5 animate-fade-in">
                        <div className="bg-slate-900 p-4 rounded-full shadow-2xl border border-indigo-500/50 mb-3 animate-bounce-subtle">
                            <LockClosedIcon className="w-8 h-8 text-indigo-400" />
                        </div>
                        <p className="text-sm font-bold text-white bg-slate-900/80 px-4 py-2 rounded-lg shadow-lg border border-white/10">
                            Complete o P1 e P2 para liberar
                        </p>
                    </div>
                )}

                {/* ELIMINATION MODE INDICATOR */}
                {isEliminationMode && !isLocked && (
                    <div className="absolute -top-10 left-0 w-full flex justify-center pointer-events-none z-30">
                        <div className="bg-rose-500 text-white px-4 py-1 rounded-full text-xs font-black uppercase tracking-widest shadow-lg animate-pulse flex items-center gap-2">
                            <TrashIcon className="w-3 h-3" /> Modo Eliminação Ativo
                        </div>
                    </div>
                )}

                {/* Options List */}
                <div className={`space-y-2 transition-all duration-500 ${isLocked ? 'opacity-30 filter blur-[3px] pointer-events-none' : 'opacity-100'}`} id="answers-block">
                    {keysToRender.map((key) => {
                        const value = question.options[key];
                        if (!value) return null;

                        const displayValue = sanitizeOptionText(value as string);
                        const isEliminated = eliminatedOptions.includes(key);
                        const isSelected = selectedOption === key;
                        const isCorrect = question.correctAnswer === key;
                        const highlights = evidence?.options[key]; 

                        let btnClass = "w-full text-left p-3.5 rounded-xl border-2 transition-all flex gap-3 items-start group ";

                        if (isEliminated) {
                             btnClass += "bg-slate-900/50 border-transparent opacity-40 grayscale decoration-slate-500 line-through cursor-not-allowed";
                        } else if (isRevealed) {
                            if (isCorrect) {
                                btnClass += "bg-emerald-500/20 border-emerald-500 text-emerald-100";
                            } else if (isSelected) {
                                btnClass += "bg-rose-500/20 border-rose-500 text-rose-100";
                            } else {
                                btnClass += "bg-white/5 border-white/5 opacity-50";
                            }
                        } else {
                            if (isEliminationMode) {
                                btnClass += "bg-white/5 border-rose-500/30 hover:bg-rose-500/10 hover:border-rose-500 text-slate-300 cursor-crosshair";
                            } else if (isSelected) {
                                btnClass += "bg-sky-600 border-sky-500 text-white shadow-lg";
                            } else {
                                btnClass += "bg-white/5 border-white/10 hover:border-sky-500/30 hover:bg-white/10 active:scale-[0.99]";
                            }
                        }

                        return (
                            <button
                                key={key}
                                onClick={() => handleOptionClick(key)}
                                disabled={isRevealed || (isLocked)}
                                className={btnClass}
                            >
                                <strong className={`shrink-0 text-base ${!isRevealed && !isSelected && !isEliminated ? 'text-sky-500 group-hover:text-sky-400' : 'text-current'}`}>{key})</strong>
                                <span className="leading-snug pt-0.5 text-sm md:text-base w-full">
                                    <PromptText text={displayValue} highlights={highlights} />
                                </span>
                                {isRevealed && isCorrect && <CheckCircleIcon className="w-5 h-5 ml-auto shrink-0 text-emerald-400" />}
                                {isRevealed && isSelected && !isCorrect && <XCircleIcon className="w-5 h-5 ml-auto shrink-0 text-rose-400" />}
                                {!isRevealed && isEliminated && <TrashIcon className="w-4 h-4 ml-auto shrink-0 text-slate-600" />}
                            </button>
                        );
                    })}
                </div>
            </div>

            {isRevealed && (
                <div className="animate-fade-in pt-6 border-t border-white/10">
                   <QuestionExplanationBlocks 
                        question={question} 
                        userAnswer={selectedOption} 
                        showTitle={true}
                   />
                </div>
            )}
        </div>
    );
};

export default QuestionViewer;

import React, { createContext, useContext, useState, useEffect, ReactNode, useCallback, useMemo } from 'react';
import { Question, AppSettings, ImportMode } from '../types';
import * as srs from '../services/srsService';
import { SAMPLE_QUESTIONS } from './sample-data';
import { saveData, loadData } from '../services/storage';
import { useSettings } from './SettingsContext';
import { ensureQuestionOptions } from '../services/questionParser';
import { migrateAllQuestions, normalizeQuestion } from '../services/migrationService';
import { traceService } from '../services/traceService';
import { attemptService, AttemptPayload } from '../services/attemptService';
import { isStrictQuestion } from '../services/contentGate';

const LS_QUESTIONS_KEY = 'revApp_questions_v5_react';

const QuestionStateContext = createContext<Question[] | undefined>(undefined);

interface QuestionDispatch {
  addQuestion: (newQuestion: Omit<Question, 'id'>) => void;
  updateQuestion: (updatedQuestion: Question) => void;
  updateBatchQuestions: (updates: ({ id: string } & Partial<Omit<Question, 'id'>>)[]) => void;
  deleteQuestions: (ids: string[]) => void;
  resetAllProgress: (settings: AppSettings) => void;
  addBatchQuestions: (newQuestions: Omit<Question, 'id'>[], mode?: ImportMode) => { imported: number, blocked: number, updated: number };
  removeDuplicates: () => number;
  registerAttempt: (payload: AttemptPayload) => void;
}

const QuestionDispatchContext = createContext<QuestionDispatch | undefined>(undefined);

export const QuestionProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const { logSystemError, settings } = useSettings();
  const [questions, setQuestions] = useState<Question[]>([]);
  const [isLoaded, setIsLoaded] = useState(false);

  useEffect(() => {
    async function load() {
        try {
            traceService.trace('BOOT_START', 'BOOT');
            const data = await loadData<any[]>(LS_QUESTIONS_KEY);
            let finalQuestions: Question[] = [];

            if (data && Array.isArray(data)) {
                // Apply strict migration but ALLOW Gaps to be loaded
                const rawMigrated = migrateAllQuestions(data);
                finalQuestions = rawMigrated; // Do not filter isStrictQuestion here to allow Trail Gaps

                console.log(`[QuestionContext] Loaded & Migrated ${finalQuestions.length} items.`);
                traceService.trace('BOOT_LOADED', 'BOOT', undefined, { count: finalQuestions.length });
            } else {
                finalQuestions = migrateAllQuestions(SAMPLE_QUESTIONS.map((q, i) => ({...q, id: `q_sample_${i}`})));
            }

            setQuestions(finalQuestions);
            traceService.snapshot('ON_APP_BOOT', { questions: finalQuestions });
        } catch (error) {
            logSystemError(error, 'QuestionContext Load');
            traceService.trace('BOOT_ERROR', 'BOOT', undefined, { error });
        } finally {
            setIsLoaded(true);
        }
    }
    load();
  }, [logSystemError]);

  useEffect(() => {
    if (!isLoaded) return;
    saveData(LS_QUESTIONS_KEY, questions).catch(e => logSystemError(e, 'QuestionContext Save'));
  }, [questions, isLoaded, logSystemError]);

  const addQuestion = useCallback((newQuestionData: Omit<Question, 'id'>) => {
    const normalizedData = normalizeQuestion({ ...newQuestionData, id: 'temp' }, newQuestionData.lawRef || '');
    const { id, ...cleanData } = normalizedData;

    // Warn but allow adding gaps manually if really needed, though usually UI prevents it
    if (!isStrictQuestion(normalizedData as Question) && !newQuestionData.isGapType) {
        console.warn("[QuestionContext] Adding item that doesn't look like a standard question.");
    }

    const fingerprint = srs.generateQuestionFingerprint(cleanData as any);

    setQuestions(prev => {
        if (prev.some(q => q.fingerprint === fingerprint)) {
            console.warn("Duplicate blocked:", cleanData.questionRef);
            return prev;
        }
        const finalId = normalizedData.id && !normalizedData.id.startsWith('temp') 
            ? normalizedData.id 
            : `q_${Date.now()}_${Math.random().toString(36).substring(2, 7)}`;

        traceService.trace('QUESTION_ADD', 'QUESTIONS', finalId, { ref: normalizedData.questionRef });
        return [...prev, { ...cleanData, fingerprint, id: finalId } as Question];
    });
  }, []);

  const addBatchQuestions = useCallback((newQuestions: Omit<Question, 'id'>[], mode: ImportMode = 'SKIP') => {
    let imported = 0;
    let blocked = 0;
    let updated = 0;

    traceService.trace('BATCH_ADD_START', 'QUESTIONS', undefined, { count: newQuestions.length, mode });

    setQuestions(prev => {
        const existingById = new Map<string, Question>(prev.map(q => [q.id, q]));
        const existingByRef = new Map<string, Question>(prev.map(q => [q.questionRef, q]));
        const existingFingerprints = new Set(prev.map(q => q.fingerprint));

        const finalBatch: Question[] = [];
        const updates: Question[] = [];

        newQuestions.forEach((q, idx) => {
            const inputId = (q as any).id;
            const hasStableId = inputId && !inputId.toString().startsWith('temp');
            const normalized = normalizeQuestion({ ...q, id: hasStableId ? inputId : 'temp' }, q.lawRef || '');
            const fingerprint = srs.generateQuestionFingerprint(normalized);

            let existing: Question | undefined;
            if (hasStableId) existing = existingById.get(normalized.id);
            if (!existing) existing = existingByRef.get(normalized.questionRef);

            if (existing) {
                if (mode === 'SKIP') {
                    blocked++;
                } else if (mode === 'MERGE') {
                    const updatedQ = { ...existing };
                    let hasChanges = false;
                    const fieldsToCheck: (keyof Question)[] = [
                        'explanationTech', 'explanationStory', 'feynmanQuestions', 
                        'distractorProfile', 'wrongDiagnosis', 'wrongDiagnosisMap',
                        'rawImportBlock', 'lawRef', 'guiaTrapscan', 'keyDistinction', 'anchorText',
                        'questionText', 'options', 'correctAnswer' 
                    ];

                    fieldsToCheck.forEach(key => {
                        const val = normalized[key];
                        if ((!updatedQ[key] || (typeof updatedQ[key] === 'object' && Object.keys(updatedQ[key] || {}).length === 0)) && val) {
                            (updatedQ as any)[key] = val;
                            hasChanges = true;
                        }
                    });

                    if (hasChanges) {
                        updates.push(updatedQ);
                        updated++;
                    } else {
                        blocked++;
                    }
                } else if (mode === 'OVERWRITE') {
                    const updatedQ: Question = {
                        ...existing,
                        ...normalized,
                        id: existing.id, 
                        totalAttempts: existing.totalAttempts,
                        masteryScore: existing.masteryScore,
                        stability: existing.stability,
                        nextReviewDate: existing.nextReviewDate,
                        attemptHistory: existing.attemptHistory,
                        lastAttemptDate: existing.lastAttemptDate,
                        lastWasCorrect: existing.lastWasCorrect,
                    };
                    updates.push(updatedQ);
                    updated++;
                }
            } else {
                if (mode === 'SKIP' && existingFingerprints.has(fingerprint)) {
                     blocked++;
                } else {
                    const finalId = normalized.id && !normalized.id.startsWith('temp') 
                        ? normalized.id 
                        : `q_batch_${Date.now()}_${idx}_${Math.random().toString(36).substring(2, 5)}`;

                    finalBatch.push({ ...normalized, fingerprint, id: finalId });
                    existingFingerprints.add(fingerprint);
                    imported++;
                }
            }
        });

        const updatedIds = new Set(updates.map(u => u.id));
        const nextState = prev.map(q => updatedIds.has(q.id) ? updates.find(u => u.id === q.id)! : q);
        const finalState = [...nextState, ...finalBatch];

        return finalState;
    });

    return { imported, blocked, updated };
  }, []);

  const removeDuplicates = useCallback(() => {
      let removedCount = 0;
      setQuestions(prev => {
          const seen = new Set<string>();
          const filtered = prev.filter(q => {
              const fp = q.fingerprint || srs.generateQuestionFingerprint(q);
              if (seen.has(fp)) {
                  removedCount++;
                  return false;
              }
              seen.add(fp);
              return true;
          });
          return filtered;
      });
      return removedCount;
  }, []);

  const updateQuestion = useCallback((updatedQuestion: Question) => {
    const finalQ = normalizeQuestion(updatedQuestion, updatedQuestion.lawRef);
    const canonicalId = srs.getCanonicalId(finalQ.id);

    setQuestions(prev => prev.map(q => {
        if (srs.getCanonicalId(q.id) === canonicalId) {
            return finalQ;
        }
        return q;
    }));
  }, []);

  const updateBatchQuestions = useCallback((updates: ({ id: string } & Partial<Omit<Question, 'id'>>)[]) => {
    setQuestions(prev => {
        const updatesMap = new Map(updates.map(u => [srs.getCanonicalId(u.id), u]));
        return prev.map(q => {
            const update = updatesMap.get(srs.getCanonicalId(q.id));
            return update ? { ...q, ...update } : q;
        });
    });
  }, []);

  const deleteQuestions = useCallback((ids: string[]) => {
    const idsSet = new Set(ids.map(id => srs.getCanonicalId(id)));
    const now = new Date().toISOString();

    traceService.trace('QUESTION_DELETE', 'QUESTIONS', undefined, { count: ids.length, type: 'SOFT_DELETE' });

    setQuestions(prev => prev.map(q => {
        if (idsSet.has(srs.getCanonicalId(q.id))) {
            return { ...q, deletedAt: now };
        }
        return q;
    }));
  }, []);

  const resetAllProgress = useCallback((settings: AppSettings) => {
    setQuestions(prev => prev.map(q => ({
      ...q,
      totalAttempts: 0,
      correctStreak: 0,
      errorCount: 0,
      masteryScore: 0,
      stability: settings.srsV2.S_default_days,
      nextReviewDate: srs.todayISO(),
      lastAttemptDate: '',
      attemptHistory: [],
      masteryHistory: [],
      srsStage: 0,
      lastWasCorrect: false,
      recentError: 0,
      lastReviewedAt: undefined,
    })));
  }, []);

  const registerAttempt = useCallback((payload: AttemptPayload) => {
      // Extended payload to allow optional orderKeys from runner hacks
      // We accept `any` here to allow components to pass extra data without breaking signature in other places immediately
      const { question, isCorrect, userAnswer, timeSec, trapCode } = payload;
      const extraData = (payload as any).trapscanData; // Access potential extra data attached

      setQuestions(prev => {
          let targetIndex = prev.findIndex(q => q.id === question.id);
          let targetQ = targetIndex !== -1 ? prev[targetIndex] : question;

          const selfEval = isCorrect ? 3 : 0;
          const srsResult = srs.calculateNewSrsState(targetQ, isCorrect, selfEval, timeSec, settings);

          const updatedQ: Question = {
              ...targetQ,
              ...srsResult,
              yourAnswer: userAnswer,
              totalAttempts: (targetQ.totalAttempts || 0) + 1,
              correctStreak: isCorrect ? (targetQ.correctStreak || 0) + 1 : 0,
              errorCount: !isCorrect ? (targetQ.errorCount || 0) + 1 : targetQ.errorCount,
              lastWasCorrect: isCorrect,
              recentError: !isCorrect ? 1 : 0,
              attemptHistory: [
                  ...(targetQ.attemptHistory || []),
                  {
                      date: srsResult.lastReviewedAt!,
                      wasCorrect: isCorrect,
                      masteryAfter: srsResult.masteryScore!,
                      stabilityAfter: srsResult.stability,
                      timeSec: Math.round(timeSec),
                      selfEvalLevel: selfEval,
                      timingClass: srsResult.timingClass,
                      targetSec: srsResult.targetSec,
                      trapCode,
                      // Hack: Check if we passed orderKeys via trapCode object or dedicated field
                      // Realistically, the component calls registerAttempt. We should update AttemptPayload type in services.
                      // But for this change, let's extract it if present in the Question object passed (which might have been enriched temporarily)
                      // Or rely on the fact that `QuestionRunner` will pass it via `trapscanData` if we hacked it there.
                      // Actually, let's trust the `extraData` passed if available.
                      orderKeys: extraData?.orderKeys
                  }
              ]
          };

          const newState = [...prev];
          if (targetIndex !== -1) {
              newState[targetIndex] = updatedQ;
          } else {
               newState.push(updatedQ);
          }

          attemptService.notify(payload);
          return newState;
      });
  }, [settings]);

  const dispatchValue = useMemo(() => ({
    addQuestion, updateQuestion, updateBatchQuestions, deleteQuestions, resetAllProgress, addBatchQuestions, removeDuplicates, registerAttempt
  }), [addQuestion, updateQuestion, updateBatchQuestions, deleteQuestions, resetAllProgress, addBatchQuestions, removeDuplicates, registerAttempt]);

  const visibleQuestions = useMemo(() => questions.filter(q => !q.deletedAt), [questions]);

  return (
    <QuestionStateContext.Provider value={visibleQuestions}>
        <QuestionDispatchContext.Provider value={dispatchValue}>
            {children}
        </QuestionDispatchContext.Provider>
    </QuestionStateContext.Provider>
  );
};

export const useQuestionState = () => {
  const context = useContext(QuestionStateContext);
  if (context === undefined) throw new Error('useQuestionState error');
  return context;
};

export const useQuestionDispatch = () => {
  const context = useContext(QuestionDispatchContext);
  if (context === undefined) throw new Error('useQuestionDispatch error');
  return context;
};

import React, { useState } from 'react';
import ReactDOM from 'react-dom';
import { Question, TrapscanEntry } from '../types';
import { useQuestionDispatch } from '../contexts/QuestionContext';
import { useSettings } from '../contexts/SettingsContext';
import * as srs from '../services/srsService';
import { detectTrapFailure } from '../services/trapscanService';
import ReviewHistoryModal from './ReviewHistoryModal';
import { QuestionContextType } from './QuestionActionsMenu';
import TrapscanPreflightModal from './TrapscanPreflightModal'; 
import { useTrapscanPreflight } from '../hooks/useTrapscanPreflight';
import QuestionRunner from './QuestionRunner'; // IMPORT RUNNER
import EditQuestionModal from './EditQuestionModal';

interface InteractiveQuestionModalProps {
    question: Question;
    onClose: () => void;
    onQuestionAnswered: (q: Question) => void;
    context?: QuestionContextType;
}

const InteractiveQuestionModal: React.FC<InteractiveQuestionModalProps> = ({ question: initialQuestion, onClose, onQuestionAnswered, context = 'questions' }) => {
    const { registerAttempt, updateQuestion, deleteQuestions } = useQuestionDispatch();
    const { settings, addXp } = useSettings();

    // PREFLIGHT HOOK
    const { isPreflightOpen, sessionConfig, handleConfirmPreflight } = useTrapscanPreflight(settings);

    // State
    const [question, setQuestion] = useState<Question>(initialQuestion);
    const [reportingQuestionAfterAnswer, setReportingQuestionAfterAnswer] = useState<Question | null>(null);
    const [masteryBefore, setMasteryBefore] = useState<number>(0);
    const [isEditing, setIsEditing] = useState(false);

    // FIX: Using 'any' for trapscanData to accept the extended structure with orderKeys
    const handleRunnerResult = (rating: 'again' | 'hard' | 'good' | 'easy', timeTaken: number, trapscanData?: any) => {
        let isCorrectNow = true;
        let evalLevel = 2;
        if (rating === 'again') { evalLevel = 0; isCorrectNow = false; }
        else if (rating === 'hard') evalLevel = 1;
        else if (rating === 'good') evalLevel = 2;
        else if (rating === 'easy') evalLevel = 3;

        if (settings.enableSoundEffects) {
            isCorrectNow ? srs.playCorrectSound() : srs.playIncorrectSound();
        }
        if (isCorrectNow) addXp(10, "Acerto!");
        else addXp(2, "Esforço!");

        setMasteryBefore(srs.calculateCurrentDomain(question, settings));

        let trapCode = isCorrectNow ? 'CODE_CORRECT' : 'SRS_ERROR';

        // Extract orderKeys from the extended data object passed by QuestionRunner
        const orderKeys = trapscanData?.orderKeys;

        // Register Attempt with extended payload hack (trapscanData field holds orderKeys)
        registerAttempt({
            question,
            isCorrect: isCorrectNow,
            userAnswer: isCorrectNow ? question.correctAnswer : 'ERROR', 
            timeSec: timeTaken,
            mode: 'SRS',
            trapCode,
            // @ts-ignore - Dynamic prop passing
            trapscanData: { ...trapscanData, orderKeys }
        });

        // Optimistic Update for UI
        const updates = srs.calculateNewSrsState(question, isCorrectNow, evalLevel, timeTaken, settings);

        const updatedQuestion: Question = {
            ...question,
            yourAnswer: isCorrectNow ? question.correctAnswer : 'ERROR',
            ...updates,
            totalAttempts: (question.totalAttempts || 0) + 1,
            attemptHistory: [
                ...(question.attemptHistory || []),
                {
                    date: new Date().toISOString(),
                    wasCorrect: isCorrectNow,
                    masteryAfter: updates.masteryScore!,
                    stabilityAfter: updates.stability,
                    timeSec: Math.round(timeTaken),
                    selfEvalLevel: evalLevel,
                    trapCode,
                    trapscanData,
                    orderKeys
                }
            ]
        };

        setReportingQuestionAfterAnswer(updatedQuestion);

        if (!settings.showHistoryAfterAnswer) {
            onQuestionAnswered(updatedQuestion);
            onClose();
        }
    };

    const handleNext = () => {
        if (reportingQuestionAfterAnswer) {
             onQuestionAnswered(reportingQuestionAfterAnswer);
             onClose();
        }
    };

    const handleEdit = (q: Question) => {
        setIsEditing(true);
    };

    const handleDelete = (id: string) => {
        deleteQuestions([id]);
        onClose();
    };

    const handleSaveEdit = (updatedQ: Question) => {
        updateQuestion(updatedQ);
        setQuestion(updatedQ);
        setIsEditing(false);
    };

    // Theme
    const isDark = settings.appTheme === 'dark' || settings.appTheme === 'galaxy';
    const themeStyles = (isDark ? {
        '--q-surface': 'rgba(15, 23, 42, 0.95)',
        '--q-text': '#F1F5F9',
        '--q-muted': '#94A3B8',
        '--q-border': 'rgba(255, 255, 255, 0.1)',
        '--q-card-bg': 'rgba(30, 41, 59, 0.5)',
        '--q-hover': 'rgba(255, 255, 255, 0.05)',
        '--q-correct-bg': 'rgba(16, 185, 129, 0.2)',
        '--q-correct-border': '#10B981',
        '--q-correct-text': '#FFFFFF',
        '--q-error-bg': 'rgba(244, 63, 94, 0.2)',
        '--q-error-border': '#F43F5E',
        '--q-error-text': '#FFFFFF',
    } : {
        '--q-surface': '#FFFFFF',
        '--q-text': '#0F172A',
        '--q-muted': '#475569',
        '--q-border': '#E2E8F0',
        '--q-card-bg': '#F8FAFC',
        '--q-hover': '#F1F5F9',
        '--q-correct-bg': '#ECFDF5',
        '--q-correct-border': '#10B981',
        '--q-correct-text': '#065F46',
        '--q-error-bg': '#FFF1F2',
        '--q-error-border': '#F43F5E',
        '--q-error-text': '#9F1239',
    }) as unknown as React.CSSProperties;

    return ReactDOM.createPortal(
        <div className={isDark ? "dark" : ""} style={themeStyles}>

            <TrapscanPreflightModal 
                isOpen={isPreflightOpen && !reportingQuestionAfterAnswer && !isEditing} 
                onConfirm={handleConfirmPreflight}
                onCancel={() => { }}
            />

            <div className={`fixed inset-0 z-[9999] flex flex-col bg-black/80 backdrop-blur-sm items-center justify-center md:p-4 transition-opacity duration-300 ${isPreflightOpen && !isEditing ? 'opacity-0 pointer-events-none' : 'opacity-100'}`} onClick={onClose}>
                <div 
                    className="bg-[var(--q-surface)] text-[var(--q-text)] w-full h-[100dvh] md:h-[90vh] md:max-w-2xl md:rounded-3xl shadow-2xl border border-[var(--q-border)] flex flex-col overflow-hidden transition-all duration-300"
                    onClick={e => e.stopPropagation()}
                >
                    <QuestionRunner 
                        question={question}
                        sessionConfig={sessionConfig}
                        onResult={handleRunnerResult}
                        onNext={handleNext}
                        isLast={true}
                        onClose={onClose}
                        context={context}
                        mode="SRS"
                        onEdit={handleEdit}
                        onDelete={handleDelete}
                    />

                    {reportingQuestionAfterAnswer && (
                        <ReviewHistoryModal
                            isOpen={!!reportingQuestionAfterAnswer}
                            onClose={() => { setReportingQuestionAfterAnswer(null); onQuestionAnswered(reportingQuestionAfterAnswer); onClose(); }}
                            question={reportingQuestionAfterAnswer}
                            onContinue={() => { setReportingQuestionAfterAnswer(null); onQuestionAnswered(reportingQuestionAfterAnswer); onClose(); }}
                            masteryBefore={masteryBefore}
                        />
                    )}
                </div>
            </div>

            {isEditing && (
                <EditQuestionModal
                    question={question}
                    onClose={() => setIsEditing(false)}
                    onSave={handleSaveEdit}
                />
            )}
        </div>,
        document.body
    );
};

