import { sanitizeOptionText } from '../services/questionParser';

interface QuestionViewerProps {
    question: Question;
    selectedOption: string | null;
    isRevealed: boolean;
    onOptionSelect?: (key: string) => void;
    className?: string;
    showMedia?: boolean;
    isLocked?: boolean; 

    eliminatedOptions?: string[];
    onEliminate?: (key: string) => void;
    isEliminationMode?: boolean;
    highlightText?: string;

    evidence?: { stem: EvidenceItem[], options: Record<string, EvidenceItem[]> } | undefined;
    orderedKeys?: string[]; // SHUFFLE: Array of keys in display order
}

const QuestionViewer: React.FC<QuestionViewerProps> = ({ 
    question, 
    selectedOption, 
    isRevealed, 
    onOptionSelect, 
    className = "",
    showMedia = true,
    isLocked = false,
    eliminatedOptions = [],
    onEliminate,
    isEliminationMode = false,
    highlightText,
    evidence,
    orderedKeys
}) => {

    const handleOptionClick = (key: string) => {
        if (isLocked) return;

        if (isEliminationMode && onEliminate) {
            onEliminate(key);
            return;
        }

        if (eliminatedOptions.includes(key)) return;

        if (!isRevealed && onOptionSelect) {
            onOptionSelect(key);
        }
    };

    // Detect if this should be rendered as a Gap/Cloze question
    const isGapMode = useMemo(() => {
        if (question.isGapType) return true;
        const text = question.questionText || '';
        return /\{\{.+?\}\}|_{3,}/.test(text);
    }, [question]);

    const renderQuestionText = () => {
        if (!isGapMode && highlightText && question.questionText.includes(highlightText)) {
            const parts = question.questionText.split(highlightText);
            return (
                <span>
                    {parts.map((part, i) => (
                        <React.Fragment key={i}>
                            <PromptText text={part} className="inline" />
                            {i < parts.length - 1 && (
                                <span className="bg-sky-500/30 text-white px-1 rounded animate-pulse font-bold border-b-2 border-sky-500">
                                    {highlightText}
                                </span>
                            )}
                        </React.Fragment>
                    ))}
                </span>
            );
        }

        return (
            <PromptText 
                text={question.questionText} 
                mode={isGapMode ? 'gap' : 'plain'}
                revealExpected={isRevealed}
                highlights={evidence?.stem} 
            />
        );
    };

    // Determine list of keys to render
    const keysToRender = useMemo(() => {
        const allowedKeys = ['A', 'B', 'C', 'D', 'E'];

        // Defensive check: Only include keys that actually have content
        const validAvailableKeys = Object.keys(question.options || {})
            .filter(k => {
                if (!allowedKeys.includes(k)) return false;
                const val = question.options[k];
                // STRICT CHECK: Value must actally exist and not be a placeholder
                if (!val || typeof val !== 'string' || val.trim() === '') return false;
                // Double check for the bug "correta" pattern
                if (val.trim().toLowerCase() === 'correta' || val.trim().toLowerCase() === 'incorreta') return false;
                return true;
            });

        if (orderedKeys && orderedKeys.length > 0) {
            // Filter orderedKeys to ensure they are valid and present
            return orderedKeys.filter(k => validAvailableKeys.includes(k));
        }

        return validAvailableKeys.sort();
    }, [orderedKeys, question.options]);

    return (
        <div className={`space-y-6 pb-10 ${className}`}>
            <div id="question-start-anchor" className="h-px w-full -mt-2"></div>

            {showMedia && (question.questionImage || question.questionAudio) && (
                <div className="flex flex-col gap-4 mb-4">
                    {question.questionImage && <img src={question.questionImage} alt="Questão" className="max-w-full rounded-lg max-h-80 object-contain mx-auto bg-black/20" />}
                    {question.questionAudio && <audio controls src={question.questionAudio} className="w-full" />}
                </div>
            )}

            {/* Question Text */}
            <div className="text-base md:text-lg font-medium leading-relaxed text-slate-200">
                {renderQuestionText()}
            </div>

            <div className="relative">
                {/* LOCKED OVERLAY */}
                {isLocked && (
                    <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-slate-900/10 backdrop-blur-sm rounded-xl border border-white/5 animate-fade-in">
                        <div className="bg-slate-900 p-4 rounded-full shadow-2xl border border-indigo-500/50 mb-3 animate-bounce-subtle">
                            <LockClosedIcon className="w-8 h-8 text-indigo-400" />
                        </div>
                        <p className="text-sm font-bold text-white bg-slate-900/80 px-4 py-2 rounded-lg shadow-lg border border-white/10">
                            Complete o P1 e P2 para liberar
                        </p>
                    </div>
                )}

                {/* ELIMINATION MODE INDICATOR */}
                {isEliminationMode && !isLocked && (
                    <div className="absolute -top-10 left-0 w-full flex justify-center pointer-events-none z-30">
                        <div className="bg-rose-500 text-white px-4 py-1 rounded-full text-xs font-black uppercase tracking-widest shadow-lg animate-pulse flex items-center gap-2">
                            <TrashIcon className="w-3 h-3" /> Modo Eliminação Ativo
                        </div>
                    </div>
                )}

                {/* Options List */}
                <div className={`space-y-2 transition-all duration-500 ${isLocked ? 'opacity-30 filter blur-[3px] pointer-events-none' : 'opacity-100'}`} id="answers-block">
                    {keysToRender.map((key, index) => {
                        const value = question.options[key];
                        // Redundant safety check in render loop
                        if (!value || value.trim() === '') return null;

                        const displayValue = sanitizeOptionText(value as string);
                        // If sanitization emptied it (e.g. was 'correta'), skip render
                        if (!displayValue) return null;

                        const isEliminated = eliminatedOptions.includes(key);
                        const isSelected = selectedOption === key;
                        const isCorrect = question.correctAnswer === key;
                        const highlights = evidence?.options[key]; 

                        // POSITIONAL LABEL: Uses index (A, B, C...) instead of original key to avoid confusion when shuffled
                        // Ex: Original Key "C" might be in position 0, so it renders as "A)"
                        const visualLabel = String.fromCharCode(65 + index); // 65 = 'A'

                        let btnClass = "w-full text-left p-3.5 rounded-xl border-2 transition-all flex gap-3 items-start group ";

                        if (isEliminated) {
                             btnClass += "bg-slate-900/50 border-transparent opacity-40 grayscale decoration-slate-500 line-through cursor-not-allowed";
                        } else if (isRevealed) {
                            if (isCorrect) {
                                btnClass += "bg-emerald-500/20 border-emerald-500 text-emerald-100";
                            } else if (isSelected) {
                                btnClass += "bg-rose-500/20 border-rose-500 text-rose-100";
                            } else {
                                btnClass += "bg-white/5 border-white/5 opacity-50";
                            }
                        } else {
                            if (isEliminationMode) {
                                btnClass += "bg-white/5 border-rose-500/30 hover:bg-rose-500/10 hover:border-rose-500 text-slate-300 cursor-crosshair";
                            } else if (isSelected) {
                                btnClass += "bg-sky-600 border-sky-500 text-white shadow-lg";
                            } else {
                                btnClass += "bg-white/5 border-white/10 hover:border-sky-500/30 hover:bg-white/10 active:scale-[0.99]";
                            }
                        }

                        return (
                            <button
                                key={key}
                                onClick={() => handleOptionClick(key)}
                                disabled={isRevealed || (isLocked)}
                                className={btnClass}
                            >
                                <strong className={`shrink-0 text-base ${!isRevealed && !isSelected && !isEliminated ? 'text-sky-500 group-hover:text-sky-400' : 'text-current'}`}>{visualLabel})</strong>
                                <span className="leading-snug pt-0.5 text-sm md:text-base w-full">
                                    <PromptText text={displayValue} highlights={highlights} />
                                </span>
                                {isRevealed && isCorrect && <CheckCircleIcon className="w-5 h-5 ml-auto shrink-0 text-emerald-400" />}
                                {isRevealed && isSelected && !isCorrect && <XCircleIcon className="w-5 h-5 ml-auto shrink-0 text-rose-400" />}
                                {!isRevealed && isEliminated && <TrashIcon className="w-4 h-4 ml-auto shrink-0 text-slate-600" />}
                            </button>
                        );
                    })}
                </div>
            </div>

            {isRevealed && (
                <div className="animate-fade-in pt-6 border-t border-white/10">
                   <QuestionExplanationBlocks 
                        question={question} 
                        userAnswer={selectedOption} 
                        showTitle={true}
                   />
                </div>
            )}
        </div>
    );
};

export default QuestionViewer;

import React, { useState, useRef } from 'react';
import { useQuestionDispatch, useQuestionState } from '../../../contexts/QuestionContext';
import { Question, ImportMode } from '../../../types';
import * as srs from '../../../services/srsService';
import { useSettings } from '../../../contexts/SettingsContext';
import { UploadIcon, ClipboardListIcon, CheckCircleIcon, BoltIcon, ExclamationTriangleIcon } from '../../../components/icons';
import { parseQuestionText } from '../../../services/questionParser';
import { normalizeDiscipline } from '../../../services/taxonomyService';

interface ImportTxtTabProps {
  setActiveTab: (tab: 'list') => void;
}

interface ParsedResult {
    newQuestions: Omit<Question, 'id'>[];
    duplicates: string[];
    errors: { blockNumber: number, text: string, message: string }[];
}

const ImportTxtTab: React.FC<ImportTxtTabProps> = ({ setActiveTab }) => {
    const { addBatchQuestions } = useQuestionDispatch();
    const allQuestions = useQuestionState();
    const { settings } = useSettings();
    const [text, setText] = useState('');
    const [analysis, setAnalysis] = useState<ParsedResult | null>(null);
    const [copied, setCopied] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [importMode, setImportMode] = useState<ImportMode>('MERGE');

    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (e) => {
            const content = e.target?.result as string;
            setText(content);
            setAnalysis(null); 
        };
        reader.readAsText(file);
        event.target.value = ''; 
    };

    const triggerFileInput = () => {
        fileInputRef.current?.click();
    };

    // --- NORMALIZADOR DE CHAVES ---
    const normalizeKey = (rawKey: string): string => {
        return rawKey.trim().toUpperCase()
            .normalize("NFD").replace(/[\u0300-\u036f]/g, "") 
            .replace(/[^A-Z0-9_]/g, "_") 
            .replace(/_+/g, "_"); 
    };

    // --- SECTION-AWARE PARSER ---
    const parseBlock = (block: string): Partial<Question> & { answer?: string, bankStyle?: string, hot?: string, crit?: string, fund?: string } => {
        const lines = block.split('\n');

        // Initial State
        const result: any = { options: {}, distractorProfile: {}, wrongDiagnosisMap: {} };
        let currentSection: 'METADATA' | 'OPTIONS' | 'PROFILE' | 'DIAGNOSIS' = 'METADATA';
        let lastKey: string | null = null;

        lines.forEach(line => {
            const trimmed = line.trim();
            if (!trimmed) return;

            // 1. Detect Section Headers
            if (/^(DISTRACTOR_PROFILE|PERFIL_DISTRATORES)[:=]/i.test(trimmed)) { 
                const content = trimmed.replace(/^(DISTRACTOR_PROFILE|PERFIL_DISTRATORES)[:=]\s*/i, '').trim();
                if (content.length > 0) {
                    // Try to parse inline: A=X | B=Y
                    const parts = content.split('|');
                    parts.forEach(p => {
                        const m = p.trim().match(/^([A-E])\s*=\s*(.*)$/);
                        if (m) result.distractorProfile[m[1]] = m[2];
                    });
                    currentSection = 'METADATA'; 
                } else {
                    currentSection = 'PROFILE'; 
                }
                return; 
            }

            if (/^(WRONG_DIAGNOSIS_MAP|MAPA_ERRO)[:=]/i.test(trimmed)) { 
                const content = trimmed.replace(/^(WRONG_DIAGNOSIS_MAP|MAPA_ERRO)[:=]\s*/i, '').trim();
                if (content.length > 0) {
                    // Try to parse inline: A=X || B=Y (Double pipe is safer for this field)
                    const parts = content.includes('||') ? content.split('||') : content.split('|');
                    parts.forEach(p => {
                         const m = p.trim().match(/^([A-E])\s*=\s*(.*)$/);
                         if (m) result.wrongDiagnosisMap[m[1]] = m[2];
                    });
                    currentSection = 'METADATA';
                } else {
                    currentSection = 'DIAGNOSIS'; 
                }
                return; 
            }

            if (/^(Q_TEXT|QUESTION_TEXT|ENUNCIADO)[:=]/i.test(trimmed)) {
                const textContent = trimmed.replace(/^(Q_TEXT|QUESTION_TEXT|ENUNCIADO)[:=]\s*/i, '');
                result.Q_TEXT = textContent;
                currentSection = 'OPTIONS';
                lastKey = 'Q_TEXT';
                return;
            }
            if (/^(CORRECT|ANSWER|GABARITO)[:=]/i.test(trimmed)) {
                currentSection = 'METADATA'; 
            }

            // 2. Handle Options / Map Entries
            if (currentSection === 'DIAGNOSIS') {
                const wdMatch = trimmed.match(/^(?:WD_|WDMAP_)?([A-E])[:=\)\-]\s*(.*)$/);
                if (wdMatch) {
                    result.wrongDiagnosisMap[wdMatch[1]] = wdMatch[2];
                    lastKey = `DIAG_${wdMatch[1]}`; 
                    return;
                }
            }

            const optionMatch = trimmed.match(/^([A-E])[:=\)\-]\s*(.*)$/);

            if (optionMatch) {
                const letter = optionMatch[1];
                const content = optionMatch[2];

                if (currentSection === 'PROFILE') {
                    result.distractorProfile[letter] = content;
                    lastKey = `PROF_${letter}`;
                } else if (currentSection === 'DIAGNOSIS') {
                    result.wrongDiagnosisMap[letter] = content;
                    lastKey = `DIAG_${letter}`;
                } else if (currentSection === 'OPTIONS') {
                    // FIX: ONLY capture options if in OPTIONS section!
                    if (!content.startsWith('WD_') && !content.includes('|') && content.toLowerCase() !== 'correta') {
                         result.options[letter] = content;
                         lastKey = `OPT_${letter}`;
                    }
                }
                // If section is METADATA, we ignore "A:" lines because they are likely inside an explanation
                return;
            }

            // 3. Handle General Metadata Keys
            const keyMatch = trimmed.match(/^([A-Za-z0-9_À-ÿ\s]+):\s*(.*)$/);
            if (keyMatch) {
                const rawKey = keyMatch[1];
                const value = keyMatch[2];
                const normalizedKey = normalizeKey(rawKey);

                if (!['DISTRACTOR_PROFILE', 'PERFIL_DISTRATORES', 'WRONG_DIAGNOSIS_MAP', 'MAPA_ERRO', 'Q_TEXT', 'ENUNCIADO'].includes(normalizedKey)) {
                    if (normalizedKey === 'ANSWER' || normalizedKey === 'GABARITO') result.answer = value;
                    else if (normalizedKey === 'BANK_STYLE') result.bankStyle = value;
                    else if (normalizedKey === 'HOT') result.hot = value;
                    else if (normalizedKey === 'CRIT') result.crit = value;
                    else if (normalizedKey === 'FUND') result.fund = value;
                    else if (normalizedKey === 'WRONG_DIAGNOSIS' || normalizedKey === 'DIAGNOSTICO_ERRO') result.WRONG_DIAGNOSIS = value;
                    else result[normalizedKey] = value;

                    lastKey = normalizedKey;
                    if (normalizedKey === 'CORRECT' || normalizedKey === 'ANSWER') currentSection = 'METADATA';

                    // Also switch to metadata if we hit Explanation headers
                    if (normalizedKey.includes('EXPLANATION') || normalizedKey.includes('COMENTARIO')) currentSection = 'METADATA';
                }
                return;
            }

            // 4. Handle Multiline Append
            if (lastKey) {
                if (lastKey === 'Q_TEXT') {
                    result.Q_TEXT = (result.Q_TEXT || '') + '\n' + trimmed;
                } else if (lastKey.startsWith('OPT_') && currentSection === 'OPTIONS') {
                    const letter = lastKey.replace('OPT_', '');
                    if (result.options[letter]) result.options[letter] += '\n' + trimmed;
                } else {
                    // Only append metadata fields if not in options
                    if (lastKey.startsWith('OPT_') && currentSection !== 'OPTIONS') return; 
                    result[lastKey] = (result[lastKey] || '') + '\n' + trimmed;
                }
            }
        });

        return result;
    }

    const handleParse = () => {
        const blocks = text.split(/(?:^Q_REF:)|(?:^----------------------\s*)/m).filter(b => b.trim());

        if (blocks.length > 50) {
            alert(`Limite de 50 questões por vez. Encontradas: ${blocks.length}.`);
            return;
        }

        const existingRefs = new Set(allQuestions.map(q => q.questionRef));
        const results: ParsedResult = { newQuestions: [], duplicates: [], errors: [] };
        let nextSequenceNumber = allQuestions.length > 0 ? Math.max(...allQuestions.map(q => q.sequenceNumber)) + 1 : 1;

        blocks.forEach((rawBlock, index) => {
            const block = rawBlock.includes('Q_REF:') ? rawBlock : `Q_REF: ${rawBlock}`; 
            try {
                const rawFields: any = parseBlock(block);

                const fields = {
                    Q_REF: rawFields.Q_REF,
                    Q_TEXT: rawFields.Q_TEXT,
                    CORRECT: rawFields.CORRECT,
                    ANSWER: rawFields.answer,
                    DISCIPLINE: rawFields.DISCIPLINE || rawFields.DISCIPLINA,
                    SUBJECT: rawFields.SUBJECT || rawFields.ASSUNTO,
                    TOPIC: rawFields.TOPIC || rawFields.TOPICO,
                    SUBTOPIC: rawFields.SUBTOPIC || rawFields.SUBTOPICO,

                    ANCHOR_TEXT: rawFields.ANCHOR_TEXT || rawFields.FRASE_ANCORA_FINAL || rawFields.FRASE_ANCORA,
                    KEY_DISTINCTION: rawFields.KEY_DISTINCTION || rawFields.PALAVRA_QUE_SALVA || rawFields.PALAVRA_CHAVE_ERRO,
                    GUIA_TRAPSCAN: rawFields.GUIA_TRAPSCAN || rawFields.TRAPSCAN,

                    BANK: rawFields.BANK || rawFields.BANCA,
                    EXAM: rawFields.EXAM || rawFields.POSITION || rawFields.CARGO,
                    TYPE: rawFields.TYPE || rawFields.TIPO,

                    EXPLANATION: rawFields.EXPLANATION || rawFields.COMENTARIO,
                    EXPLANATION_TECH: rawFields.EXPLANATION_TECH || rawFields.EXPLICA_TECNICA,
                    EXPLANATION_STORY: rawFields.EXPLANATION_STORY || rawFields.STORYTELLING || rawFields.HISTORIA,
                    PERGUNTAS_FEYNMAN: rawFields.PERGUNTAS_FEYNMAN || rawFields.FEYNMAN,

                    WRONG_DIAGNOSIS: rawFields.WRONG_DIAGNOSIS || rawFields.DIAGNOSTICO_ERRO,

                    OPT_A: rawFields.options?.A || rawFields.OPT_A,
                    OPT_B: rawFields.options?.B || rawFields.OPT_B,
                    OPT_C: rawFields.options?.C || rawFields.OPT_C,
                    OPT_D: rawFields.options?.D || rawFields.OPT_D,
                    OPT_E: rawFields.options?.E || rawFields.OPT_E,

                    // Maps - Guaranteed to be objects from parseBlock
                    distractorProfile: rawFields.distractorProfile,
                    wrongDiagnosisMap: rawFields.wrongDiagnosisMap,

                    HOT: rawFields.hot || rawFields.HOT,
                    CRIT: rawFields.crit || rawFields.CRIT,
                    FUND: rawFields.fund || rawFields.FUND,

                    // TRILHA Support: Use LAW_REF if present, explicitly bypassing strict Lei Seca validation
                    // The srsService.canonicalizeLitRef will handle preservation of 'TRILHA_' prefix.
                    LAW_REF: rawFields.LAW_REF || rawFields.LIT_REF,
                    LIT_REF: rawFields.LIT_REF
                };

                if (!fields.Q_REF || !fields.Q_TEXT) {
                     if (block.length > 50 && !fields.Q_REF) throw new Error('Campo Q_REF obrigatório não encontrado.');
                     else return; 
                }

                if (existingRefs.has(fields.Q_REF)) results.duplicates.push(fields.Q_REF);

                const isCebraspe = (fields.BANK || '').toUpperCase().includes('CEBRASPE') || 
                                   (fields.TYPE || '').includes('C/E');

                let correctAnswer = (fields.CORRECT || '').toUpperCase().trim();
                const matchAns = correctAnswer.match(/^([A-E])/);
                if (matchAns) correctAnswer = matchAns[1];

                if (!correctAnswer && fields.ANSWER) {
                     const ans = fields.ANSWER.toUpperCase().trim();
                     if (ans === 'CERTO' || ans === 'C') correctAnswer = 'A';
                     else if (ans === 'ERRADO' || ans === 'E') correctAnswer = 'B';
                }

                if (!correctAnswer) throw new Error('Gabarito ausente (CORRECT ou ANSWER).');

                let options: any = { A: fields.OPT_A, B: fields.OPT_B, C: fields.OPT_C, D: fields.OPT_D, E: fields.OPT_E };

                if (isCebraspe && !options.A && !options.C) {
                    options = { A: 'Certo', B: 'Errado', C: '—', D: '—', E: '—' };
                }

                let qText = fields.Q_TEXT;
                if (!isCebraspe) {
                    const hasExplicitOptions = Object.values(options).some(v => !!v);
                    if (!hasExplicitOptions) {
                        const parsed = parseQuestionText(fields.Q_TEXT);
                        if (Object.keys(parsed.options).length > 0) {
                            options = { ...options, ...parsed.options };
                            qText = parsed.stem;
                        }
                    }
                }

                const newQuestion: Omit<Question, 'id'> = {
                    sequenceNumber: nextSequenceNumber++,
                    bank: fields.BANK || '',
                    position: fields.EXAM || '',
                    subject: normalizeDiscipline(fields.DISCIPLINE || 'Geral'),
                    topic: fields.SUBJECT || fields.TOPIC || 'Geral',
                    subtopic: fields.SUBTOPIC,

                    // Prioritize LAW_REF, fallback to LIT_REF, then empty string.
                    // If LAW_REF starts with TRILHA_, it will be preserved by srsService.
                    lawRef: fields.LAW_REF || fields.LIT_REF || '',
                    litRef: fields.LIT_REF,

                    anchorText: fields.ANCHOR_TEXT,
                    keyDistinction: fields.KEY_DISTINCTION,
                    guiaTrapscan: fields.GUIA_TRAPSCAN,

                    area: fields.SUBJECT || fields.DISCIPLINE || 'Geral',
                    questionRef: fields.Q_REF,
                    questionText: qText,
                    options: options,

                    explanation: fields.EXPLANATION_TECH || fields.EXPLANATION || '',
                    explanationTech: fields.EXPLANATION_TECH,
                    explanationStory: fields.EXPLANATION_STORY,
                    feynmanQuestions: fields.PERGUNTAS_FEYNMAN,

                    comments: '',
                    correctAnswer: correctAnswer,
                    questionType: fields.TYPE || (isCebraspe ? '13 C/E' : 'Literalidade'),
                    createdAt: srs.todayISO(),
                    lastAttemptDate: '',
                    totalAttempts: 0,
                    errorCount: 0,
                    lastWasCorrect: false,
                    timeSec: 0,
                    selfEvalLevel: 0,
                    masteryScore: 0,
                    stability: settings.srsV2?.S_default_days ?? 1,
                    lastReviewedAt: undefined,
                    nextReviewDate: srs.todayISO(),
                    willFallExam: false,
                    srsStage: 0,
                    correctStreak: 0,
                    attemptHistory: [],
                    srsVersion: 2,
                    recentError: 0,
                    difficulty: 0.5,
                    difficultyLevel: 'normal',

                    wrongDiagnosis: fields.WRONG_DIAGNOSIS,
                    distractorProfile: fields.distractorProfile,
                    wrongDiagnosisMap: fields.wrongDiagnosisMap,
                    rawImportBlock: block,

                    hotTopic: !!fields.HOT,
                    isCritical: !!fields.CRIT,
                    isFundamental: !!fields.FUND
                };

                results.newQuestions.push(newQuestion);
                if (existingRefs.has(fields.Q_REF)) {
                    results.duplicates.push(fields.Q_REF);
                }

            } catch (e: any) {
                results.errors.push({ blockNumber: index + 1, text: block.substring(0, 50) + '...', message: e.message });
            }
        });

        setAnalysis(results);
    };

    const handleImport = () => {
        if (!analysis || analysis.newQuestions.length === 0) {
            alert("Nenhuma questão nova para importar.");
            return;
        }

        const { imported, updated, blocked } = addBatchQuestions(analysis.newQuestions, importMode);

        let msg = `Processamento concluído (${importMode}).\n`;
        msg += `Novas: ${imported}\n`;
        msg += `Atualizadas: ${updated}\n`;
        msg += `Ignoradas: ${blocked}`;

        alert(msg);
        setText('');
        setAnalysis(null);
    };

    const runParserTests = () => {
         alert("Teste: Cole o texto no campo e clique em 'Analisar Texto' para ver o resultado.");
    };

    const example = `
Q_REF: TRILHA_CONT_SEFAZMT_AUTO_Q01
LAW_REF: TRILHA_CONT_SEFAZMT_AUTO
DISCIPLINE: Direito Tributario
Q_TEXT: Exemplo de questão de trilha...
A: Opção A
B: Opção B
CORRECT: B
`.trim();

    const handleCopy = () => { navigator.clipboard.writeText(example); setCopied(true); setTimeout(() => setCopied(false), 2000); };

    return (
        <div className="max-w-4xl mx-auto space-y-4">
            <div className="p-6 bg-bunker-100 dark:bg-bunker-900 rounded-lg">
                <div className="flex justify-between items-start mb-4">
                    <div>
                        <h3 className="font-bold text-lg">Importar Questões em Lote</h3>
                        <p className="text-sm text-bunker-500 dark:text-bunker-400 mt-2">
                            Cole o texto ou carregue um arquivo .txt. Suporta formato de Trilha e Lei Seca.
                        </p>
                    </div>
                     <button onClick={runParserTests} className="px-3 py-1 bg-amber-500/10 text-amber-500 border border-amber-500/20 rounded-lg text-[10px] font-bold uppercase tracking-widest hover:bg-amber-500/20 transition-colors flex items-center gap-2">
                        <BoltIcon className="w-3 h-3" /> Ajuda / Teste
                    </button>
                </div>

                <div className="relative group my-4">
                    <pre className="text-xs p-3 bg-bunker-50 dark:bg-bunker-800 rounded-md overflow-x-auto whitespace-pre-wrap font-mono border border-bunker-200 dark:border-bunker-700 pr-10"><code>{example}</code></pre>
                    <button onClick={handleCopy} className="absolute top-2 right-2 p-1.5 rounded-lg bg-bunker-200 dark:bg-bunker-700 text-bunker-500 hover:text-white hover:bg-sky-500 transition-all opacity-0 group-hover:opacity-100 focus:opacity-100">
                        {copied ? <CheckCircleIcon className="w-4 h-4 text-emerald-500" /> : <ClipboardListIcon className="w-4 h-4" />}
                    </button>
                </div>

                <div>
                     <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".txt" className="hidden" />
                    <div className="flex justify-between items-center mb-2">
                        <button onClick={triggerFileInput} className="text-xs font-bold text-sky-500 hover:underline flex items-center gap-1">
                            <UploadIcon className="w-3 h-3"/> Carregar Arquivo
                        </button>
                    </div>
                </div>

                <textarea value={text} onChange={(e) => setText(e.target.value)} rows={12} placeholder="Cole o conteúdo aqui... Ex: Q_REF: TRILHA_..." className="w-full font-mono text-xs bg-bunker-50 dark:bg-bunker-800 border border-bunker-200 dark:border-bunker-700 rounded-md p-2 focus:ring-sky-500 focus:border-sky-500" />
                <div className="mt-4 flex justify-between items-center">
                    <span className="text-xs text-bunker-400">{text.length > 0 ? `${text.length} caracteres` : ''}</span>
                    <button onClick={handleParse} className="bg-sky-500/20 text-sky-700 dark:text-sky-300 font-bold py-2 px-4 rounded-lg hover:bg-sky-500/30 transition-colors">Analisar Texto</button>
                </div>
            </div>
            {analysis && (
                <div className="p-4 bg-bunker-50 dark:bg-bunker-800/50 rounded-lg space-y-4 animate-fade-in border border-bunker-200 dark:border-bunker-700">
                    <div className="flex justify-between items-center">
                        <h4 className="font-bold text-lg">Resultado da Análise</h4>
                        <div className="flex gap-1 bg-bunker-200 dark:bg-bunker-800 p-1 rounded-lg">
                             <button onClick={() => setImportMode('SKIP')} className={`px-3 py-1 rounded text-xs font-bold ${importMode === 'SKIP' ? 'bg-white dark:bg-bunker-600 shadow' : 'text-slate-500'}`}>Ignorar Duplicatas</button>
                             <button onClick={() => setImportMode('MERGE')} className={`px-3 py-1 rounded text-xs font-bold ${importMode === 'MERGE' ? 'bg-sky-500 text-white shadow' : 'text-slate-500'}`}>Mesclar (Completar)</button>
                             <button onClick={() => setImportMode('OVERWRITE')} className={`px-3 py-1 rounded text-xs font-bold ${importMode === 'OVERWRITE' ? 'bg-amber-500 text-white shadow' : 'text-slate-500'}`}>Sobrescrever</button>
                        </div>
                    </div>

                    {analysis.errors.length > 0 && (
                        <div className="p-3 bg-red-500/10 rounded-md border border-red-500/20">
                            <h5 className="font-bold text-red-500 mb-2">{analysis.errors.length} Erro(s):</h5>
                            <ul className="list-disc list-inside text-sm text-red-600 dark:text-red-400 space-y-2 max-h-48 overflow-y-auto">
                                {analysis.errors.map((e, i) => <li key={i}><strong>Bloco {e.blockNumber}:</strong> {e.message}</li>)}
                            </ul>
                        </div>
                    )}

                    <div className="grid grid-cols-2 gap-4">
                        <div className="p-3 bg-emerald-500/10 rounded-md text-emerald-700 dark:text-emerald-300 border border-emerald-500/20 text-center">
                            <span className="block text-2xl font-bold">{analysis.newQuestions.length}</span>
                            <span className="text-xs uppercase font-bold">Identificadas</span>
                        </div>
                         <div className="p-3 bg-amber-500/10 rounded-md text-amber-700 dark:text-amber-300 border border-amber-500/20 text-center">
                            <span className="block text-2xl font-bold">{analysis.duplicates.length}</span>
                            <span className="text-xs uppercase font-bold">Já Existem (Q_REF)</span>
                        </div>
                    </div>

                    <div className="flex justify-end">
                        <button onClick={handleImport} disabled={analysis.newQuestions.length === 0} className="bg-emerald-500 text-white font-bold py-2 px-6 rounded-lg shadow-md hover:bg-emerald-600 disabled:opacity-50 transition-colors">
                            Processar ({importMode})
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default ImportTxtTab;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Question, TrapscanEntry, TrapscanSessionConfig } from '../types';
import { useSettings } from '../contexts/SettingsContext';
import * as trapscanLogic from '../services/trapscanLogic';
import { 
    XMarkIcon, LockClosedIcon, ArrowRightIcon, 
    ExclamationTriangleIcon, FullScreenIcon, ExitFullScreenIcon
} from './icons';
import QuestionViewer from './QuestionViewer';
import TrapscanGate from './TrapscanGate';
import QuestionActionsMenu, { QuestionContextType } from './QuestionActionsMenu';
import ReadingContainer from './ui/ReadingContainer';
import { getText } from '../utils/i18nText';
import { isStrictQuestion } from '../services/contentGate';
import ConfirmationModal from './ConfirmationModal';
import { useQuestionDispatch } from '../contexts/QuestionContext';
import { sanitizeOptionText } from '../services/questionParser';

interface QuestionRunnerProps {
    question: Question;
    sessionConfig?: TrapscanSessionConfig | null;
    onResult: (rating: 'again' | 'hard' | 'good' | 'easy', timeTaken: number, trapscanData?: TrapscanEntry) => void;
    onNext?: () => void;
    isLast?: boolean;
    onClose?: () => void;
    context: QuestionContextType;
    mode?: 'SRS' | 'SIMPLE';
    allowGaps?: boolean;
    onEdit?: (q: Question) => void;
    onDelete?: (id: string) => void;
}

const MediaBlock: React.FC<{ image?: string, audio?: string }> = ({ image, audio }) => {
    if (!image && !audio) return null;
    return (
        <div className="flex flex-col gap-3 items-center mb-6 w-full animate-fade-in" onClick={e => e.stopPropagation()}>
           {image && (
               <img src={image} alt="Mídia da Questão" className="max-w-full max-h-72 rounded-2xl shadow-2xl object-contain bg-black/20" />
           )}
           {audio && (
               <audio controls src={audio} className="w-full max-w-md h-10 opacity-90 hover:opacity-100 transition-opacity" />
           )}
        </div>
    );
};

// Fisher-Yates Shuffle
function shuffleArray<T>(array: T[]): T[] {
    const arr = [...array];
    for (let i = arr.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [arr[i], arr[j]] = [arr[j], arr[i]];
    }
    return arr;
}

const QuestionRunner: React.FC<QuestionRunnerProps> = ({ 
    question, 
    sessionConfig, 
    onResult, 
    onNext, 
    isLast, 
    onClose, 
    context,
    mode = 'SRS',
    allowGaps = false,
    onEdit,
    onDelete
}) => {
    const { settings, updateSettings, addXp } = useSettings();
    const { deleteQuestions, registerAttempt } = useQuestionDispatch();
    const scrollRef = useRef<HTMLDivElement>(null);
    const startTimeRef = useRef<number>(Date.now());

    const isInvalidContent = !allowGaps && !isStrictQuestion(question);

    // Shuffle Logic State
    const [orderedKeys, setOrderedKeys] = useState<string[]>([]);

    useEffect(() => {
        if (isInvalidContent) {
            console.warn("[QuestionRunner] Conteúdo inválido detectado. Pulando...", question.id);
            if (onNext) {
                const t = setTimeout(onNext, 100);
                return () => clearTimeout(t);
            }
        }
    }, [question.id, isInvalidContent, onNext]);

    // --- SHUFFLE LOGIC ---
    useEffect(() => {
        if (!question.options) {
             setOrderedKeys([]);
             return;
        }

        // STRICT KEY FILTER: Only allow valid option keys (A-E) AND non-empty content
        const allowedKeys = ['A', 'B', 'C', 'D', 'E'];
        const validKeys = Object.keys(question.options)
            .filter(k => {
                if (!allowedKeys.includes(k)) return false;
                const val = question.options[k];
                // Check if value exists and is not sanitized away
                if (!val || !sanitizeOptionText(val)) return false;
                return true;
            });

        // Check if settings enabled
        if (settings.shuffleAlternatives && !question.isGapType) {
            // Exceptions: Don't shuffle True/False or C/E types if explicit
            // Or if strict 2 options that are C/E.
            const isCebraspe = (question.options['C'] === 'Certo' && question.options['E'] === 'Errado');
            if (isCebraspe) {
                // Keep explicit C/E order if those keys exist
                setOrderedKeys(validKeys.sort()); 
            } else {
                setOrderedKeys(shuffleArray(validKeys));
            }
        } else {
            setOrderedKeys(validKeys.sort()); // Default A-Z
        }
    }, [question.id, settings.shuffleAlternatives, question.options, question.isGapType]);

    const [isDeleteConfirmOpen, setIsDeleteConfirmOpen] = useState(false);

    if (isInvalidContent) {
        return (
            <div className="flex flex-col items-center justify-center h-full p-10 text-center space-y-4">
                <ExclamationTriangleIcon className="w-12 h-12 text-amber-500 opacity-50" />
                <h3 className="text-xl font-bold text-white">Conteúdo Incompatível</h3>
                <p className="text-slate-400 text-sm">Este item parece ser uma lacuna em modo questão. Pulando...</p>
                <button onClick={onNext} className="bg-white/10 px-6 py-2 rounded-lg text-sm font-bold uppercase hover:bg-white/20">
                    Forçar Pulo
                </button>
            </div>
        );
    }

    const activeConfig: TrapscanSessionConfig = useMemo(() => {
        if (sessionConfig) return sessionConfig;
        const defaults = { enabled: true, assistMode: true, defaultMode: 'TREINO' as const, lockLevel: 'SOFT' as const };
        return (settings.trapscan as TrapscanSessionConfig) || defaults;
    }, [sessionConfig, settings.trapscan]);

    const [selectedOption, setSelectedOption] = useState<string | null>(null);
    const [isRevealed, setIsRevealed] = useState(false);
    const [trapscanData, setTrapscanData] = useState<TrapscanEntry | undefined>(undefined);
    const [showBlockToast, setShowBlockToast] = useState<string | null>(null);

    const [eliminatedOptions, setEliminatedOptions] = useState<string[]>([]);
    const [isEliminationMode, setIsEliminationMode] = useState(false);
    const [highlightAnchor, setHighlightAnchor] = useState(false);

    useEffect(() => {
        setSelectedOption(null);
        setIsRevealed(false);
        setTrapscanData(undefined);
        setEliminatedOptions([]);
        setIsEliminationMode(false);
        setHighlightAnchor(false);
        setIsDeleteConfirmOpen(false);
        startTimeRef.current = Date.now();

        if (scrollRef.current) {
            scrollRef.current.scrollTo({ top: 0, behavior: 'instant' });
        }
    }, [question.id]);

    const isGap = allowGaps && (question.isGapType || question.questionText.includes('{{'));
    const isLocked = !isGap && trapscanLogic.checkAlternativesLocked(activeConfig, trapscanData);
    const blockReason = !isGap ? trapscanLogic.getSubmitBlockReason(activeConfig, trapscanData, !!selectedOption) : null;
    const canSubmit = !blockReason;

    const handleOptionSelect = (key: string) => {
        if (!isRevealed && !isLocked && !isEliminationMode) {
            setSelectedOption(key);
        }
    };

    const handleEliminate = (key: string) => {
        setEliminatedOptions(prev => {
             if (prev.includes(key)) return prev.filter(k => k !== key);
             return [...prev, key];
        });
    };

    const handleReveal = () => {
        if (!canSubmit) {
            setShowBlockToast(blockReason);
            setTimeout(() => setShowBlockToast(null), 3000);
            return;
        }
        setIsRevealed(true);
    };

    const handleRating = (rating: 'again' | 'hard' | 'good' | 'easy') => {
        const timeTaken = (Date.now() - startTimeRef.current) / 1000;
        // @ts-ignore - Dynamic addition
        const enhancedTrapscanData = { ...trapscanData, orderKeys: orderedKeys };

        onResult(rating, timeTaken, enhancedTrapscanData);
        if (onNext) onNext();
    };

    const handleSimpleNext = () => {
        const isCorrect = selectedOption === question.correctAnswer;
        const timeTaken = (Date.now() - startTimeRef.current) / 1000;
        // @ts-ignore
        const enhancedTrapscanData = { ...trapscanData, orderKeys: orderedKeys };
        onResult(isCorrect ? 'good' : 'again', timeTaken, enhancedTrapscanData);
        if (onNext) onNext();
    };

    const toggleReaderMode = () => {
        const newMode = settings.readerMode === 'compact' ? 'fullscreen' : 'compact';
        updateSettings({ readerMode: newMode });
    };

    const handleDeleteRequest = (id: string) => {
        setIsDeleteConfirmOpen(true);
    };

    const handleConfirmDelete = () => {
        deleteQuestions([question.id]);
        if (onDelete) onDelete(question.id);
        if (onNext) onNext();
        setIsDeleteConfirmOpen(false);
    };

    const showTrapscan = !isGap && trapscanLogic.isTrapscanActive(activeConfig) && !question.isGapType;

    return (
        <div className="flex flex-col h-full bg-[var(--q-surface)] text-[var(--q-text)] relative">
            <header className="px-5 py-4 border-b border-[var(--q-border)] flex justify-between items-center bg-[var(--q-surface)] backdrop-blur-md shrink-0 z-10">
                <div className="min-w-0 pr-4">
                    <h2 className="text-sm font-extrabold tracking-tight truncate uppercase italic">{question.questionRef}</h2>
                    <p className="text-[10px] font-semibold text-[var(--q-muted)] uppercase mt-0.5">{question.subject}</p>
                </div>
                <div className="flex items-center gap-2">
                    {activeConfig?.enabled && showTrapscan && (
                        <div className={`hidden sm:block px-2 py-0.5 rounded text-[9px] font-black uppercase border ${activeConfig.assistMode ? 'bg-indigo-500/10 border-indigo-500/30 text-indigo-400' : 'bg-slate-500/10 border-slate-500/30 text-slate-500'}`}>
                            {activeConfig.assistMode ? (activeConfig.defaultMode === 'GUIA' ? 'GUIA' : `LOCK: ${activeConfig.lockLevel}`) : 'OFF'}
                        </div>
                    )}

                    <button 
                        onClick={toggleReaderMode}
                        className="p-2 rounded-lg text-[var(--q-muted)] hover:bg-[var(--q-hover)] transition-colors hidden sm:block"
                        title={settings.readerMode === 'compact' ? "Expandir Tela" : "Modo Leitura"}
                    >
                        {settings.readerMode === 'compact' ? <FullScreenIcon className="w-5 h-5"/> : <ExitFullScreenIcon className="w-5 h-5"/>}
                    </button>

                    <QuestionActionsMenu 
                        question={question} 
                        context={context} 
                        onEdit={onEdit} 
                        onDelete={handleDeleteRequest} 
                    />

                    {onClose && (
                        <button onClick={onClose} className="p-2 -mr-2 text-[var(--q-muted)] hover:bg-[var(--q-hover)] transition-colors">
                            <XMarkIcon className="w-5 h-5"/>
                        </button>
                    )}
                </div>
            </header>

            <div className="flex-1 overflow-y-auto custom-scrollbar" ref={scrollRef}>
                 <ReadingContainer mode={settings.readerMode} className="py-6 pb-24 md:py-8">
                      <MediaBlock image={question.questionImage} audio={question.questionAudio} />

                      {showTrapscan && !isRevealed && (
                          <TrapscanGate 
                              question={question}
                              isLocked={isLocked}
                              onUnlock={() => {}} 
                              onAllowSubmit={() => {}} 
                              onUpdate={setTrapscanData}
                              userAnswer={selectedOption}
                              configOverride={activeConfig}
                              eliminatedOptions={eliminatedOptions}
                              onSetEliminationMode={setIsEliminationMode}
                              onSetHighlightAnchor={setHighlightAnchor}
                          />
                      )}

                      <QuestionViewer 
                          question={question}
                          selectedOption={selectedOption}
                          isRevealed={isRevealed}
                          onOptionSelect={handleOptionSelect}
                          showMedia={false} 
                          isLocked={isLocked}
                          isEliminationMode={isEliminationMode}
                          eliminatedOptions={eliminatedOptions}
                          onEliminate={handleEliminate}
                          highlightText={highlightAnchor ? getText(question.anchorText) : undefined}
                          orderedKeys={orderedKeys.length > 0 ? orderedKeys : undefined} // Pass shuffled order
                      />
                  </ReadingContainer>
            </div>

            {showBlockToast && (
                <div className="absolute bottom-24 left-1/2 -translate-x-1/2 bg-rose-500 text-white px-6 py-3 rounded-full shadow-2xl font-bold text-xs uppercase tracking-widest z-50 animate-bounce-subtle flex items-center gap-2">
                    <LockClosedIcon className="w-4 h-4" />
                    {showBlockToast}
                </div>
            )}

            {selectedOption && (
                <footer className="p-5 bg-[var(--q-surface)] border-t border-[var(--q-border)] shrink-0 z-20 pb-[calc(1.5rem+env(safe-area-inset-bottom))] shadow-[0_-10px_40px_rgba(0,0,0,0.3)]">
                    <ReadingContainer mode={settings.readerMode} className="!px-0">
                        {!isRevealed ? (
                            <button 
                                onClick={handleReveal} 
                                disabled={!canSubmit && activeConfig?.assistMode && activeConfig?.defaultMode === 'TREINO'}
                                className={`w-full font-black py-4 rounded-2xl shadow-xl transition-all uppercase tracking-widest text-sm flex items-center justify-center gap-2
                                    ${canSubmit || !activeConfig?.assistMode || activeConfig?.defaultMode === 'GUIA'
                                        ? 'bg-sky-600 text-white hover:bg-sky-500 active:scale-[0.98]' 
                                        : 'bg-slate-700 text-slate-500 cursor-not-allowed opacity-80'}`}
                            >
                                {(canSubmit || !activeConfig?.assistMode || activeConfig?.defaultMode === 'GUIA') ? 'Ver Gabarito' : <><LockClosedIcon className="w-4 h-4"/> Complete o Trapscan</>}
                            </button>
                        ) : (
                            mode === 'SRS' ? (
                                <div className="grid grid-cols-4 gap-3 h-20">
                                    <button onClick={() => handleRating('again')} className="rounded-2xl bg-rose-500/10 border-2 border-rose-500/50 text-rose-500 hover:bg-rose-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Errei</span>
                                    </button>
                                    <button onClick={() => handleRating('hard')} className="rounded-2xl bg-amber-500/10 border-2 border-amber-500/50 text-amber-500 hover:bg-amber-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Difícil</span>
                                    </button>
                                    <button onClick={() => handleRating('good')} className="rounded-2xl bg-sky-500/10 border-2 border-sky-500/50 text-sky-500 hover:bg-sky-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Bom</span>
                                    </button>
                                    <button onClick={() => handleRating('easy')} className="rounded-2xl bg-emerald-500/10 border-2 border-emerald-500/50 text-emerald-500 hover:bg-emerald-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Fácil</span>
                                    </button>
                                </div>
                            ) : (
                                <button 
                                    onClick={handleSimpleNext} 
                                    className={`w-full font-black py-4 rounded-2xl shadow-xl flex items-center justify-center gap-3 uppercase tracking-widest text-xs active:scale-95 transition-all ${isLast ? 'bg-emerald-600 hover:bg-emerald-500 text-white' : 'bg-white text-slate-900 hover:bg-sky-50'}`}
                                >
                                    {isLast ? 'Finalizar' : 'Próxima'} <ArrowRightIcon className="w-4 h-4" />
                                </button>
                            )
                        )}
                    </ReadingContainer>
                </footer>
            )}

            <ConfirmationModal 
                isOpen={isDeleteConfirmOpen} 
                onClose={() => setIsDeleteConfirmOpen(false)} 
                onConfirm={handleConfirmDelete} 
                title="Excluir Questão?"
            >
                <div className="space-y-2">
                    <p className="text-sm text-slate-300">Tem certeza que deseja apagar esta questão? Ela será removida de todas as suas listas de estudo.</p>
                    <p className="text-[10px] font-black text-rose-500 uppercase tracking-widest">Ação irreversível.</p>
                </div>
            </ConfirmationModal>

        </div>
    );
};

export default QuestionRunner;

import React, { useMemo } from 'react';
import { Question, EvidenceItem } from '../types';
import { CheckCircleIcon, XCircleIcon, LockClosedIcon, TrashIcon, ScaleIcon } from './icons';
import QuestionExplanationBlocks from './QuestionExplanationBlocks';
import PromptText from './ui/PromptText';
import { sanitizeOptionText } from '../services/questionParser';

interface QuestionViewerProps {
    question: Question;
    selectedOption: string | null;
    isRevealed: boolean;
    onOptionSelect?: (key: string) => void;
    className?: string;
    showMedia?: boolean;
    isLocked?: boolean; 

    eliminatedOptions?: string[];
    onEliminate?: (key: string) => void;
    isEliminationMode?: boolean;
    highlightText?: string;

    evidence?: { stem: EvidenceItem[], options: Record<string, EvidenceItem[]> } | undefined;
    orderedKeys?: string[]; // SHUFFLE: Array of keys in display order
}

const QuestionViewer: React.FC<QuestionViewerProps> = ({ 
    question, 
    selectedOption, 
    isRevealed, 
    onOptionSelect, 
    className = "",
    showMedia = true,
    isLocked = false,
    eliminatedOptions = [],
    onEliminate,
    isEliminationMode = false,
    highlightText,
    evidence,
    orderedKeys
}) => {

    const handleOptionClick = (key: string) => {
        if (isLocked) return;

        if (isEliminationMode && onEliminate) {
            onEliminate(key);
            return;
        }

        if (eliminatedOptions.includes(key)) return;

        if (!isRevealed && onOptionSelect) {
            onOptionSelect(key);
        }
    };

    // Detect if this should be rendered as a Gap/Cloze question
    const isGapMode = useMemo(() => {
        if (question.isGapType) return true;
        const text = question.questionText || '';
        return /\{\{.+?\}\}|_{3,}/.test(text);
    }, [question]);

    // Detect if this is a True/False (Certo/Errado) Judgement question
    const isJudgementMode = useMemo(() => {
        if (isGapMode) return false;
        const type = (question.questionType || '').toUpperCase();
        const bank = (question.bank || '').toUpperCase();

        // Explicit Type or Bank detection
        if (type.includes('C/E') || type.includes('CERTO') || type.includes('JULGAMENTO') || type.includes('V/F')) return true;
        if (bank.includes('CESPE') || bank.includes('CEBRASPE')) return true;

        // Content detection (if options contains "Certo" and "Errado")
        const optValues = Object.values(question.options || {}).map(v => (v || '').trim().toUpperCase());
        if (optValues.includes('CERTO') && optValues.includes('ERRADO')) return true;

        return false;
    }, [question, isGapMode]);

    // Resolve keys for Certo and Errado
    const judgementKeys = useMemo(() => {
        if (!isJudgementMode) return null;
        let rightKey = '';
        let wrongKey = '';

        // 1. Try finding explicit text in options
        Object.entries(question.options || {}).forEach(([k, v]) => {
            const val = (v || '').toUpperCase().trim();
            if (val === 'CERTO') rightKey = k;
            if (val === 'ERRADO') wrongKey = k;
        });

        // 2. Fallback strategies if text didn't match perfectly but mode is detected
        if (!rightKey || !wrongKey) {
            // Standard C/E mapping (C=Certo, E=Errado)
            if (question.options['C'] && !question.options['A']) {
                rightKey = 'C'; wrongKey = 'E';
            } else {
                // Standard A/B mapping
                rightKey = 'A'; wrongKey = 'B';
            }
        }

        return { rightKey, wrongKey };
    }, [isJudgementMode, question.options]);

    const renderQuestionText = () => {
        if (!isGapMode && highlightText && question.questionText.includes(highlightText)) {
            const parts = question.questionText.split(highlightText);
            return (
                <span>
                    {parts.map((part, i) => (
                        <React.Fragment key={i}>
                            <PromptText text={part} className="inline" />
                            {i < parts.length - 1 && (
                                <span className="bg-sky-500/30 text-white px-1 rounded animate-pulse font-bold border-b-2 border-sky-500">
                                    {highlightText}
                                </span>
                            )}
                        </React.Fragment>
                    ))}
                </span>
            );
        }

        return (
            <PromptText 
                text={question.questionText} 
                mode={isGapMode ? 'gap' : 'plain'}
                revealExpected={isRevealed}
                highlights={evidence?.stem} 
            />
        );
    };

    // Determine list of keys to render for Standard Mode
    const keysToRender = useMemo(() => {
        const allowedKeys = ['A', 'B', 'C', 'D', 'E'];

        // Defensive check: Only include keys that actually have content
        const validAvailableKeys = Object.keys(question.options || {})
            .filter(k => {
                if (!allowedKeys.includes(k)) return false;
                const val = question.options[k];
                if (!val || typeof val !== 'string' || val.trim() === '') return false;
                if (val.trim().toLowerCase() === 'correta' || val.trim().toLowerCase() === 'incorreta') return false;
                return true;
            });

        if (orderedKeys && orderedKeys.length > 0) {
            // Filter orderedKeys to ensure they are valid and present
            return orderedKeys.filter(k => validAvailableKeys.includes(k));
        }

        return validAvailableKeys.sort();
    }, [orderedKeys, question.options]);

    return (
        <div className={`space-y-6 pb-10 ${className}`}>
            <div id="question-start-anchor" className="h-px w-full -mt-2"></div>

            {showMedia && (question.questionImage || question.questionAudio) && (
                <div className="flex flex-col gap-4 mb-4">
                    {question.questionImage && <img src={question.questionImage} alt="Questão" className="max-w-full rounded-lg max-h-80 object-contain mx-auto bg-black/20" />}
                    {question.questionAudio && <audio controls src={question.questionAudio} className="w-full" />}
                </div>
            )}

            {/* Question Text */}
            <div className="text-base md:text-lg font-medium leading-relaxed text-slate-200">
                {renderQuestionText()}
            </div>

            <div className="relative">
                {/* LOCKED OVERLAY */}
                {isLocked && (
                    <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-slate-900/10 backdrop-blur-sm rounded-xl border border-white/5 animate-fade-in">
                        <div className="bg-slate-900 p-4 rounded-full shadow-2xl border border-indigo-500/50 mb-3 animate-bounce-subtle">
                            <LockClosedIcon className="w-8 h-8 text-indigo-400" />
                        </div>
                        <p className="text-sm font-bold text-white bg-slate-900/80 px-4 py-2 rounded-lg shadow-lg border border-white/10">
                            Complete o P1 e P2 para liberar
                        </p>
                    </div>
                )}

                {/* ELIMINATION MODE INDICATOR */}
                {isEliminationMode && !isLocked && (
                    <div className="absolute -top-10 left-0 w-full flex justify-center pointer-events-none z-30">
                        <div className="bg-rose-500 text-white px-4 py-1 rounded-full text-xs font-black uppercase tracking-widest shadow-lg animate-pulse flex items-center gap-2">
                            <TrashIcon className="w-3 h-3" /> Modo Eliminação Ativo
                        </div>
                    </div>
                )}

                {/* SPECIAL UI FOR JUDGEMENT (CERTO/ERRADO) */}
                {isJudgementMode && judgementKeys ? (
                    <div className={`grid grid-cols-2 gap-4 mt-6 transition-all duration-500 ${isLocked ? 'opacity-30 filter blur-[3px] pointer-events-none' : 'opacity-100'}`}>
                        {/* CERTO BUTTON */}
                        <button
                            onClick={() => handleOptionClick(judgementKeys.rightKey)}
                            disabled={isRevealed || isLocked}
                            className={`
                                relative p-6 rounded-2xl border-2 flex flex-col items-center justify-center gap-2 transition-all active:scale-[0.98]
                                ${isRevealed
                                    ? (question.correctAnswer === judgementKeys.rightKey 
                                        ? 'bg-emerald-500/20 border-emerald-500 text-emerald-400' 
                                        : (selectedOption === judgementKeys.rightKey ? 'bg-rose-500/20 border-rose-500 text-rose-400' : 'bg-white/5 border-white/5 text-slate-500 opacity-50'))
                                    : (selectedOption === judgementKeys.rightKey
                                        ? 'bg-sky-600 border-sky-500 text-white shadow-lg'
                                        : 'bg-white/5 border-white/10 hover:bg-white/10 hover:border-emerald-500/50 text-slate-300')
                                }
                            `}
                        >
                            <CheckCircleIcon className="w-8 h-8 mb-1" />
                            <span className="text-lg font-black uppercase tracking-widest">Certo</span>
                        </button>

                        {/* ERRADO BUTTON */}
                        <button
                            onClick={() => handleOptionClick(judgementKeys.wrongKey)}
                            disabled={isRevealed || isLocked}
                            className={`
                                relative p-6 rounded-2xl border-2 flex flex-col items-center justify-center gap-2 transition-all active:scale-[0.98]
                                ${isRevealed
                                    ? (question.correctAnswer === judgementKeys.wrongKey 
                                        ? 'bg-emerald-500/20 border-emerald-500 text-emerald-400' 
                                        : (selectedOption === judgementKeys.wrongKey ? 'bg-rose-500/20 border-rose-500 text-rose-400' : 'bg-white/5 border-white/5 text-slate-500 opacity-50'))
                                    : (selectedOption === judgementKeys.wrongKey
                                        ? 'bg-sky-600 border-sky-500 text-white shadow-lg'
                                        : 'bg-white/5 border-white/10 hover:bg-white/10 hover:border-rose-500/50 text-slate-300')
                                }
                            `}
                        >
                            <XCircleIcon className="w-8 h-8 mb-1" />
                            <span className="text-lg font-black uppercase tracking-widest">Errado</span>
                        </button>

                        {/* Judgement Label */}
                        <div className="col-span-2 text-center mt-2">
                             <span className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.3em] flex items-center justify-center gap-2">
                                <ScaleIcon className="w-3 h-3" /> Julgue o Item
                             </span>
                        </div>
                    </div>
                ) : (
                    /* STANDARD MULTIPLE CHOICE UI */
                    <div className={`space-y-2 transition-all duration-500 ${isLocked ? 'opacity-30 filter blur-[3px] pointer-events-none' : 'opacity-100'}`} id="answers-block">
                        {keysToRender.map((key, index) => {
                            const value = question.options[key];
                            if (!value || value.trim() === '') return null;

                            const displayValue = sanitizeOptionText(value as string);
                            if (!displayValue) return null;

                            const isEliminated = eliminatedOptions.includes(key);
                            const isSelected = selectedOption === key;
                            const isCorrect = question.correctAnswer === key;
                            const highlights = evidence?.options[key]; 

                            const visualLabel = String.fromCharCode(65 + index); 

                            let btnClass = "w-full text-left p-3.5 rounded-xl border-2 transition-all flex gap-3 items-start group ";

                            if (isEliminated) {
                                btnClass += "bg-slate-900/50 border-transparent opacity-40 grayscale decoration-slate-500 line-through cursor-not-allowed";
                            } else if (isRevealed) {
                                if (isCorrect) {
                                    btnClass += "bg-emerald-500/20 border-emerald-500 text-emerald-100";
                                } else if (isSelected) {
                                    btnClass += "bg-rose-500/20 border-rose-500 text-rose-100";
                                } else {
                                    btnClass += "bg-white/5 border-white/5 opacity-50";
                                }
                            } else {
                                if (isEliminationMode) {
                                    btnClass += "bg-white/5 border-rose-500/30 hover:bg-rose-500/10 hover:border-rose-500 text-slate-300 cursor-crosshair";
                                } else if (isSelected) {
                                    btnClass += "bg-sky-600 border-sky-500 text-white shadow-lg";
                                } else {
                                    btnClass += "bg-white/5 border-white/10 hover:border-sky-500/30 hover:bg-white/10 active:scale-[0.99]";
                                }
                            }

                            return (
                                <button
                                    key={key}
                                    onClick={() => handleOptionClick(key)}
                                    disabled={isRevealed || (isLocked)}
                                    className={btnClass}
                                >
                                    <strong className={`shrink-0 text-base ${!isRevealed && !isSelected && !isEliminated ? 'text-sky-500 group-hover:text-sky-400' : 'text-current'}`}>{visualLabel})</strong>
                                    <span className="leading-snug pt-0.5 text-sm md:text-base w-full">
                                        <PromptText text={displayValue} highlights={highlights} />
                                    </span>
                                    {isRevealed && isCorrect && <CheckCircleIcon className="w-5 h-5 ml-auto shrink-0 text-emerald-400" />}
                                    {isRevealed && isSelected && !isCorrect && <XCircleIcon className="w-5 h-5 ml-auto shrink-0 text-rose-400" />}
                                    {!isRevealed && isEliminated && <TrashIcon className="w-4 h-4 ml-auto shrink-0 text-slate-600" />}
                                </button>
                            );
                        })}
                    </div>
                )}
            </div>

            {isRevealed && (
                <div className="animate-fade-in pt-6 border-t border-white/10">
                   <QuestionExplanationBlocks 
                        question={question} 
                        userAnswer={selectedOption} 
                        showTitle={true}
                   />
                </div>
            )}
        </div>
    );
};

export default QuestionViewer;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Question, TrapscanEntry, TrapscanSessionConfig } from '../types';
import { useSettings } from '../contexts/SettingsContext';
import * as trapscanLogic from '../services/trapscanLogic';
import { 
    XMarkIcon, LockClosedIcon, ArrowRightIcon, 
    ExclamationTriangleIcon, FullScreenIcon, ExitFullScreenIcon
} from './icons';
import QuestionViewer from './QuestionViewer';
import TrapscanGate from './TrapscanGate';
import QuestionActionsMenu, { QuestionContextType } from './QuestionActionsMenu';
import ReadingContainer from './ui/ReadingContainer';
import { getText } from '../utils/i18nText';
import { isStrictQuestion } from '../services/contentGate';
import ConfirmationModal from './ConfirmationModal';
import { useQuestionDispatch } from '../contexts/QuestionContext';
import { sanitizeOptionText } from '../services/questionParser';

interface QuestionRunnerProps {
    question: Question;
    sessionConfig?: TrapscanSessionConfig | null;
    onResult: (rating: 'again' | 'hard' | 'good' | 'easy', timeTaken: number, trapscanData?: TrapscanEntry) => void;
    onNext?: () => void;
    isLast?: boolean;
    onClose?: () => void;
    context: QuestionContextType;
    mode?: 'SRS' | 'SIMPLE';
    allowGaps?: boolean;
    onEdit?: (q: Question) => void;
    onDelete?: (id: string) => void;
}

const MediaBlock: React.FC<{ image?: string, audio?: string }> = ({ image, audio }) => {
    if (!image && !audio) return null;
    return (
        <div className="flex flex-col gap-3 items-center mb-6 w-full animate-fade-in" onClick={e => e.stopPropagation()}>
           {image && (
               <img src={image} alt="Mídia da Questão" className="max-w-full max-h-72 rounded-2xl shadow-2xl object-contain bg-black/20" />
           )}
           {audio && (
               <audio controls src={audio} className="w-full max-w-md h-10 opacity-90 hover:opacity-100 transition-opacity" />
           )}
        </div>
    );
};

// Fisher-Yates Shuffle
function shuffleArray<T>(array: T[]): T[] {
    const arr = [...array];
    for (let i = arr.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [arr[i], arr[j]] = [arr[j], arr[i]];
    }
    return arr;
}

const QuestionRunner: React.FC<QuestionRunnerProps> = ({ 
    question, 
    sessionConfig, 
    onResult, 
    onNext, 
    isLast, 
    onClose, 
    context,
    mode = 'SRS',
    allowGaps = false,
    onEdit,
    onDelete
}) => {
    const { settings, updateSettings, addXp } = useSettings();
    const { deleteQuestions, registerAttempt } = useQuestionDispatch();
    const scrollRef = useRef<HTMLDivElement>(null);
    const startTimeRef = useRef<number>(Date.now());

    const isInvalidContent = !allowGaps && !isStrictQuestion(question);

    // Shuffle Logic State
    const [orderedKeys, setOrderedKeys] = useState<string[]>([]);

    useEffect(() => {
        if (isInvalidContent) {
            console.warn("[QuestionRunner] Conteúdo inválido detectado. Pulando...", question.id);
            if (onNext) {
                const t = setTimeout(onNext, 100);
                return () => clearTimeout(t);
            }
        }
    }, [question.id, isInvalidContent, onNext]);

    // --- SHUFFLE LOGIC ---
    useEffect(() => {
        if (!question.options) {
             setOrderedKeys([]);
             return;
        }

        // STRICT KEY FILTER: Only allow valid option keys (A-E) AND non-empty content
        const allowedKeys = ['A', 'B', 'C', 'D', 'E'];
        const validKeys = Object.keys(question.options)
            .filter(k => {
                if (!allowedKeys.includes(k)) return false;
                const val = question.options[k];
                // Check if value exists and is not sanitized away
                if (!val || !sanitizeOptionText(val)) return false;
                return true;
            });

        // Check if settings enabled
        if (settings.shuffleAlternatives && !question.isGapType) {
            // DETECT JUDGMENT TYPE TO PREVENT SHUFFLE
            const type = (question.questionType || '').toUpperCase();
            const bank = (question.bank || '').toUpperCase();
            const isJudgement = 
                type.includes('C/E') || 
                type.includes('CERTO') || 
                type.includes('JULGAMENTO') || 
                type.includes('V/F') ||
                bank.includes('CESPE') || 
                bank.includes('CEBRASPE');

            // Also check for explicit C/E keys presence
            const hasExplicitCE = (question.options['C'] === 'Certo' && question.options['E'] === 'Errado');
            const hasImplicitCE = validKeys.length === 2 && 
                Object.values(question.options).some(v => v?.toUpperCase() === 'CERTO') &&
                Object.values(question.options).some(v => v?.toUpperCase() === 'ERRADO');

            if (isJudgement || hasExplicitCE || hasImplicitCE) {
                // Keep explicit C/E order if those keys exist
                setOrderedKeys(validKeys.sort()); 
            } else {
                setOrderedKeys(shuffleArray(validKeys));
            }
        } else {
            setOrderedKeys(validKeys.sort()); // Default A-Z
        }
    }, [question.id, settings.shuffleAlternatives, question.options, question.isGapType, question.questionType, question.bank]);

    const [isDeleteConfirmOpen, setIsDeleteConfirmOpen] = useState(false);

    if (isInvalidContent) {
        return (
            <div className="flex flex-col items-center justify-center h-full p-10 text-center space-y-4">
                <ExclamationTriangleIcon className="w-12 h-12 text-amber-500 opacity-50" />
                <h3 className="text-xl font-bold text-white">Conteúdo Incompatível</h3>
                <p className="text-slate-400 text-sm">Este item parece ser uma lacuna em modo questão. Pulando...</p>
                <button onClick={onNext} className="bg-white/10 px-6 py-2 rounded-lg text-sm font-bold uppercase hover:bg-white/20">
                    Forçar Pulo
                </button>
            </div>
        );
    }

    const activeConfig: TrapscanSessionConfig = useMemo(() => {
        if (sessionConfig) return sessionConfig;
        const defaults = { enabled: true, assistMode: true, defaultMode: 'TREINO' as const, lockLevel: 'SOFT' as const };
        return (settings.trapscan as TrapscanSessionConfig) || defaults;
    }, [sessionConfig, settings.trapscan]);

    const [selectedOption, setSelectedOption] = useState<string | null>(null);
    const [isRevealed, setIsRevealed] = useState(false);
    const [trapscanData, setTrapscanData] = useState<TrapscanEntry | undefined>(undefined);
    const [showBlockToast, setShowBlockToast] = useState<string | null>(null);

    const [eliminatedOptions, setEliminatedOptions] = useState<string[]>([]);
    const [isEliminationMode, setIsEliminationMode] = useState(false);
    const [highlightAnchor, setHighlightAnchor] = useState(false);

    useEffect(() => {
        setSelectedOption(null);
        setIsRevealed(false);
        setTrapscanData(undefined);
        setEliminatedOptions([]);
        setIsEliminationMode(false);
        setHighlightAnchor(false);
        setIsDeleteConfirmOpen(false);
        startTimeRef.current = Date.now();

        if (scrollRef.current) {
            scrollRef.current.scrollTo({ top: 0, behavior: 'instant' });
        }
    }, [question.id]);

    const isGap = allowGaps && (question.isGapType || question.questionText.includes('{{'));
    const isLocked = !isGap && trapscanLogic.checkAlternativesLocked(activeConfig, trapscanData);
    const blockReason = !isGap ? trapscanLogic.getSubmitBlockReason(activeConfig, trapscanData, !!selectedOption) : null;
    const canSubmit = !blockReason;

    const handleOptionSelect = (key: string) => {
        if (!isRevealed && !isLocked && !isEliminationMode) {
            setSelectedOption(key);
        }
    };

    const handleEliminate = (key: string) => {
        setEliminatedOptions(prev => {
             if (prev.includes(key)) return prev.filter(k => k !== key);
             return [...prev, key];
        });
    };

    const handleReveal = () => {
        if (!canSubmit) {
            setShowBlockToast(blockReason);
            setTimeout(() => setShowBlockToast(null), 3000);
            return;
        }
        setIsRevealed(true);
    };

    const handleRating = (rating: 'again' | 'hard' | 'good' | 'easy') => {
        const timeTaken = (Date.now() - startTimeRef.current) / 1000;
        // @ts-ignore - Dynamic addition
        const enhancedTrapscanData = { ...trapscanData, orderKeys: orderedKeys };

        onResult(rating, timeTaken, enhancedTrapscanData);
        if (onNext) onNext();
    };

    const handleSimpleNext = () => {
        const isCorrect = selectedOption === question.correctAnswer;
        const timeTaken = (Date.now() - startTimeRef.current) / 1000;
        // @ts-ignore
        const enhancedTrapscanData = { ...trapscanData, orderKeys: orderedKeys };
        onResult(isCorrect ? 'good' : 'again', timeTaken, enhancedTrapscanData);
        if (onNext) onNext();
    };

    const toggleReaderMode = () => {
        const newMode = settings.readerMode === 'compact' ? 'fullscreen' : 'compact';
        updateSettings({ readerMode: newMode });
    };

    const handleDeleteRequest = (id: string) => {
        setIsDeleteConfirmOpen(true);
    };

    const handleConfirmDelete = () => {
        deleteQuestions([question.id]);
        if (onDelete) onDelete(question.id);
        if (onNext) onNext();
        setIsDeleteConfirmOpen(false);
    };

    const showTrapscan = !isGap && trapscanLogic.isTrapscanActive(activeConfig) && !question.isGapType;

    return (
        <div className="flex flex-col h-full bg-[var(--q-surface)] text-[var(--q-text)] relative">
            <header className="px-5 py-4 border-b border-[var(--q-border)] flex justify-between items-center bg-[var(--q-surface)] backdrop-blur-md shrink-0 z-10">
                <div className="min-w-0 pr-4">
                    <h2 className="text-sm font-extrabold tracking-tight truncate uppercase italic">{question.questionRef}</h2>
                    <p className="text-[10px] font-semibold text-[var(--q-muted)] uppercase mt-0.5">{question.subject}</p>
                </div>
                <div className="flex items-center gap-2">
                    {activeConfig?.enabled && showTrapscan && (
                        <div className={`hidden sm:block px-2 py-0.5 rounded text-[9px] font-black uppercase border ${activeConfig.assistMode ? 'bg-indigo-500/10 border-indigo-500/30 text-indigo-400' : 'bg-slate-500/10 border-slate-500/30 text-slate-500'}`}>
                            {activeConfig.assistMode ? (activeConfig.defaultMode === 'GUIA' ? 'GUIA' : `LOCK: ${activeConfig.lockLevel}`) : 'OFF'}
                        </div>
                    )}

                    <button 
                        onClick={toggleReaderMode}
                        className="p-2 rounded-lg text-[var(--q-muted)] hover:bg-[var(--q-hover)] transition-colors hidden sm:block"
                        title={settings.readerMode === 'compact' ? "Expandir Tela" : "Modo Leitura"}
                    >
                        {settings.readerMode === 'compact' ? <FullScreenIcon className="w-5 h-5"/> : <ExitFullScreenIcon className="w-5 h-5"/>}
                    </button>

                    <QuestionActionsMenu 
                        question={question} 
                        context={context} 
                        onEdit={onEdit} 
                        onDelete={handleDeleteRequest} 
                    />

                    {onClose && (
                        <button onClick={onClose} className="p-2 -mr-2 text-[var(--q-muted)] hover:bg-[var(--q-hover)] transition-colors">
                            <XMarkIcon className="w-5 h-5"/>
                        </button>
                    )}
                </div>
            </header>

            <div className="flex-1 overflow-y-auto custom-scrollbar" ref={scrollRef}>
                 <ReadingContainer mode={settings.readerMode} className="py-6 pb-24 md:py-8">
                      <MediaBlock image={question.questionImage} audio={question.questionAudio} />

                      {showTrapscan && !isRevealed && (
                          <TrapscanGate 
                              question={question}
                              isLocked={isLocked}
                              onUnlock={() => {}} 
                              onAllowSubmit={() => {}} 
                              onUpdate={setTrapscanData}
                              userAnswer={selectedOption}
                              configOverride={activeConfig}
                              eliminatedOptions={eliminatedOptions}
                              onSetEliminationMode={setIsEliminationMode}
                              onSetHighlightAnchor={setHighlightAnchor}
                          />
                      )}

                      <QuestionViewer 
                          question={question}
                          selectedOption={selectedOption}
                          isRevealed={isRevealed}
                          onOptionSelect={handleOptionSelect}
                          showMedia={false} 
                          isLocked={isLocked}
                          isEliminationMode={isEliminationMode}
                          eliminatedOptions={eliminatedOptions}
                          onEliminate={handleEliminate}
                          highlightText={highlightAnchor ? getText(question.anchorText) : undefined}
                          orderedKeys={orderedKeys.length > 0 ? orderedKeys : undefined} // Pass shuffled order
                      />
                  </ReadingContainer>
            </div>

            {showBlockToast && (
                <div className="absolute bottom-24 left-1/2 -translate-x-1/2 bg-rose-500 text-white px-6 py-3 rounded-full shadow-2xl font-bold text-xs uppercase tracking-widest z-50 animate-bounce-subtle flex items-center gap-2">
                    <LockClosedIcon className="w-4 h-4" />
                    {showBlockToast}
                </div>
            )}

            {selectedOption && (
                <footer className="p-5 bg-[var(--q-surface)] border-t border-[var(--q-border)] shrink-0 z-20 pb-[calc(1.5rem+env(safe-area-inset-bottom))] shadow-[0_-10px_40px_rgba(0,0,0,0.3)]">
                    <ReadingContainer mode={settings.readerMode} className="!px-0">
                        {!isRevealed ? (
                            <button 
                                onClick={handleReveal} 
                                disabled={!canSubmit && activeConfig?.assistMode && activeConfig?.defaultMode === 'TREINO'}
                                className={`w-full font-black py-4 rounded-2xl shadow-xl transition-all uppercase tracking-widest text-sm flex items-center justify-center gap-2
                                    ${canSubmit || !activeConfig?.assistMode || activeConfig?.defaultMode === 'GUIA'
                                        ? 'bg-sky-600 text-white hover:bg-sky-500 active:scale-[0.98]' 
                                        : 'bg-slate-700 text-slate-500 cursor-not-allowed opacity-80'}`}
                            >
                                {(canSubmit || !activeConfig?.assistMode || activeConfig?.defaultMode === 'GUIA') ? 'Ver Gabarito' : <><LockClosedIcon className="w-4 h-4"/> Complete o Trapscan</>}
                            </button>
                        ) : (
                            mode === 'SRS' ? (
                                <div className="grid grid-cols-4 gap-3 h-20">
                                    <button onClick={() => handleRating('again')} className="rounded-2xl bg-rose-500/10 border-2 border-rose-500/50 text-rose-500 hover:bg-rose-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Errei</span>
                                    </button>
                                    <button onClick={() => handleRating('hard')} className="rounded-2xl bg-amber-500/10 border-2 border-amber-500/50 text-amber-500 hover:bg-amber-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Difícil</span>
                                    </button>
                                    <button onClick={() => handleRating('good')} className="rounded-2xl bg-sky-500/10 border-2 border-sky-500/50 text-sky-500 hover:bg-sky-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Bom</span>
                                    </button>
                                    <button onClick={() => handleRating('easy')} className="rounded-2xl bg-emerald-500/10 border-2 border-emerald-500/50 text-emerald-500 hover:bg-emerald-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Fácil</span>
                                    </button>
                                </div>
                            ) : (
                                <button 
                                    onClick={handleSimpleNext} 
                                    className={`w-full font-black py-4 rounded-2xl shadow-xl flex items-center justify-center gap-3 uppercase tracking-widest text-xs active:scale-95 transition-all ${isLast ? 'bg-emerald-600 hover:bg-emerald-500 text-white' : 'bg-white text-slate-900 hover:bg-sky-50'}`}
                                >
                                    {isLast ? 'Finalizar' : 'Próxima'} <ArrowRightIcon className="w-4 h-4" />
                                </button>
                            )
                        )}
                    </ReadingContainer>
                </footer>
            )}

            <ConfirmationModal 
                isOpen={isDeleteConfirmOpen} 
                onClose={() => setIsDeleteConfirmOpen(false)} 
                onConfirm={handleConfirmDelete} 
                title="Excluir Questão?"
            >
                <div className="space-y-2">
                    <p className="text-sm text-slate-300">Tem certeza que deseja apagar esta questão? Ela será removida de todas as suas listas de estudo.</p>
                    <p className="text-[10px] font-black text-rose-500 uppercase tracking-widest">Ação irreversível.</p>
                </div>
            </ConfirmationModal>

        </div>
    );
};

export default QuestionRunner;

import React, { useMemo } from 'react';
import { Question, EvidenceItem } from '../types';
import { CheckCircleIcon, XCircleIcon, LockClosedIcon, TrashIcon, ScaleIcon } from './icons';
import QuestionExplanationBlocks from './QuestionExplanationBlocks';
import PromptText from './ui/PromptText';
import { sanitizeOptionText } from '../services/questionParser';

interface QuestionViewerProps {
    question: Question;
    selectedOption: string | null;
    isRevealed: boolean;
    onOptionSelect?: (key: string) => void;
    className?: string;
    showMedia?: boolean;
    isLocked?: boolean; 

    eliminatedOptions?: string[];
    onEliminate?: (key: string) => void;
    isEliminationMode?: boolean;
    highlightText?: string;

    evidence?: { stem: EvidenceItem[], options: Record<string, EvidenceItem[]> } | undefined;
    orderedKeys?: string[]; // SHUFFLE: Array of keys in display order
}

const QuestionViewer: React.FC<QuestionViewerProps> = ({ 
    question, 
    selectedOption, 
    isRevealed, 
    onOptionSelect, 
    className = "",
    showMedia = true,
    isLocked = false,
    eliminatedOptions = [],
    onEliminate,
    isEliminationMode = false,
    highlightText,
    evidence,
    orderedKeys
}) => {

    const handleOptionClick = (key: string) => {
        if (isLocked) return;

        if (isEliminationMode && onEliminate) {
            onEliminate(key);
            return;
        }

        if (eliminatedOptions.includes(key)) return;

        if (!isRevealed && onOptionSelect) {
            onOptionSelect(key);
        }
    };

    // Detect if this should be rendered as a Gap/Cloze question
    const isGapMode = useMemo(() => {
        if (question.isGapType) return true;
        const text = question.questionText || '';
        return /\{\{.+?\}\}|_{3,}/.test(text);
    }, [question]);

    // Detect if this is a True/False (Certo/Errado) Judgement question
    const isJudgementMode = useMemo(() => {
        if (isGapMode) return false;
        const type = (question.questionType || '').toUpperCase();
        const bank = (question.bank || '').toUpperCase();

        // Explicit Type or Bank detection
        if (type.includes('C/E') || type.includes('CERTO') || type.includes('JULGAMENTO') || type.includes('V/F')) return true;
        if (bank.includes('CESPE') || bank.includes('CEBRASPE')) return true;

        // Content detection (if options contains "Certo" and "Errado")
        const optValues = Object.values(question.options || {}).map(v => ((v as string) || '').trim().toUpperCase());
        if (optValues.includes('CERTO') && optValues.includes('ERRADO')) return true;

        return false;
    }, [question, isGapMode]);

    // Resolve keys for Certo and Errado
    const judgementKeys = useMemo(() => {
        if (!isJudgementMode) return null;
        let rightKey = '';
        let wrongKey = '';

        // 1. Try finding explicit text in options
        Object.entries(question.options || {}).forEach(([k, v]) => {
            const val = ((v as string) || '').toUpperCase().trim();
            if (val === 'CERTO') rightKey = k;
            if (val === 'ERRADO') wrongKey = k;
        });

        // 2. Fallback strategies if text didn't match perfectly but mode is detected
        if (!rightKey || !wrongKey) {
            // Standard C/E mapping (C=Certo, E=Errado)
            if (question.options['C'] && !question.options['A']) {
                rightKey = 'C'; wrongKey = 'E';
            } else {
                // Standard A/B mapping
                rightKey = 'A'; wrongKey = 'B';
            }
        }

        return { rightKey, wrongKey };
    }, [isJudgementMode, question.options]);

    const renderQuestionText = () => {
        if (!isGapMode && highlightText && question.questionText.includes(highlightText)) {
            const parts = question.questionText.split(highlightText);
            return (
                <span>
                    {parts.map((part, i) => (
                        <React.Fragment key={i}>
                            <PromptText text={part} className="inline" />
                            {i < parts.length - 1 && (
                                <span className="bg-sky-500/30 text-white px-1 rounded animate-pulse font-bold border-b-2 border-sky-500">
                                    {highlightText}
                                </span>
                            )}
                        </React.Fragment>
                    ))}
                </span>
            );
        }

        return (
            <PromptText 
                text={question.questionText} 
                mode={isGapMode ? 'gap' : 'plain'}
                revealExpected={isRevealed}
                highlights={evidence?.stem} 
            />
        );
    };

    // Determine list of keys to render for Standard Mode
    const keysToRender = useMemo(() => {
        const allowedKeys = ['A', 'B', 'C', 'D', 'E'];

        // Defensive check: Only include keys that actually have content
        const validAvailableKeys = Object.keys(question.options || {})
            .filter(k => {
                if (!allowedKeys.includes(k)) return false;
                const val = question.options[k];
                if (!val || typeof val !== 'string' || val.trim() === '') return false;
                if (val.trim().toLowerCase() === 'correta' || val.trim().toLowerCase() === 'incorreta') return false;
                return true;
            });

        if (orderedKeys && orderedKeys.length > 0) {
            // Filter orderedKeys to ensure they are valid and present
            return orderedKeys.filter(k => validAvailableKeys.includes(k));
        }

        return validAvailableKeys.sort();
    }, [orderedKeys, question.options]);

    return (
        <div className={`space-y-6 pb-10 ${className}`}>
            <div id="question-start-anchor" className="h-px w-full -mt-2"></div>

            {showMedia && (question.questionImage || question.questionAudio) && (
                <div className="flex flex-col gap-4 mb-4">
                    {question.questionImage && <img src={question.questionImage} alt="Questão" className="max-w-full rounded-lg max-h-80 object-contain mx-auto bg-black/20" />}
                    {question.questionAudio && <audio controls src={question.questionAudio} className="w-full" />}
                </div>
            )}

            {/* Question Text */}
            <div className="text-base md:text-lg font-medium leading-relaxed text-slate-200">
                {renderQuestionText()}
            </div>

            <div className="relative">
                {/* LOCKED OVERLAY */}
                {isLocked && (
                    <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-slate-900/10 backdrop-blur-sm rounded-xl border border-white/5 animate-fade-in">
                        <div className="bg-slate-900 p-4 rounded-full shadow-2xl border border-indigo-500/50 mb-3 animate-bounce-subtle">
                            <LockClosedIcon className="w-8 h-8 text-indigo-400" />
                        </div>
                        <p className="text-sm font-bold text-white bg-slate-900/80 px-4 py-2 rounded-lg shadow-lg border border-white/10">
                            Complete o P1 e P2 para liberar
                        </p>
                    </div>
                )}

                {/* ELIMINATION MODE INDICATOR */}
                {isEliminationMode && !isLocked && (
                    <div className="absolute -top-10 left-0 w-full flex justify-center pointer-events-none z-30">
                        <div className="bg-rose-500 text-white px-4 py-1 rounded-full text-xs font-black uppercase tracking-widest shadow-lg animate-pulse flex items-center gap-2">
                            <TrashIcon className="w-3 h-3" /> Modo Eliminação Ativo
                        </div>
                    </div>
                )}

                {/* SPECIAL UI FOR JUDGEMENT (CERTO/ERRADO) */}
                {isJudgementMode && judgementKeys ? (
                    <div className={`grid grid-cols-2 gap-4 mt-6 transition-all duration-500 ${isLocked ? 'opacity-30 filter blur-[3px] pointer-events-none' : 'opacity-100'}`}>
                        {/* CERTO BUTTON */}
                        <button
                            onClick={() => handleOptionClick(judgementKeys.rightKey)}
                            disabled={isRevealed || isLocked}
                            className={`
                                relative p-6 rounded-2xl border-2 flex flex-col items-center justify-center gap-2 transition-all active:scale-[0.98]
                                ${isRevealed
                                    ? (question.correctAnswer === judgementKeys.rightKey 
                                        ? 'bg-emerald-500/20 border-emerald-500 text-emerald-400' 
                                        : (selectedOption === judgementKeys.rightKey ? 'bg-rose-500/20 border-rose-500 text-rose-400' : 'bg-white/5 border-white/5 text-slate-500 opacity-50'))
                                    : (selectedOption === judgementKeys.rightKey
                                        ? 'bg-sky-600 border-sky-500 text-white shadow-lg'
                                        : 'bg-white/5 border-white/10 hover:bg-white/10 hover:border-emerald-500/50 text-slate-300')
                                }
                            `}
                        >
                            <CheckCircleIcon className="w-8 h-8 mb-1" />
                            <span className="text-lg font-black uppercase tracking-widest">Certo</span>
                        </button>

                        {/* ERRADO BUTTON */}
                        <button
                            onClick={() => handleOptionClick(judgementKeys.wrongKey)}
                            disabled={isRevealed || isLocked}
                            className={`
                                relative p-6 rounded-2xl border-2 flex flex-col items-center justify-center gap-2 transition-all active:scale-[0.98]
                                ${isRevealed
                                    ? (question.correctAnswer === judgementKeys.wrongKey 
                                        ? 'bg-emerald-500/20 border-emerald-500 text-emerald-400' 
                                        : (selectedOption === judgementKeys.wrongKey ? 'bg-rose-500/20 border-rose-500 text-rose-400' : 'bg-white/5 border-white/5 text-slate-500 opacity-50'))
                                    : (selectedOption === judgementKeys.wrongKey
                                        ? 'bg-sky-600 border-sky-500 text-white shadow-lg'
                                        : 'bg-white/5 border-white/10 hover:bg-white/10 hover:border-rose-500/50 text-slate-300')
                                }
                            `}
                        >
                            <XCircleIcon className="w-8 h-8 mb-1" />
                            <span className="text-lg font-black uppercase tracking-widest">Errado</span>
                        </button>

                        {/* Judgement Label */}
                        <div className="col-span-2 text-center mt-2">
                             <span className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.3em] flex items-center justify-center gap-2">
                                <ScaleIcon className="w-3 h-3" /> Julgue o Item
                             </span>
                        </div>
                    </div>
                ) : (
                    /* STANDARD MULTIPLE CHOICE UI */
                    <div className={`space-y-2 transition-all duration-500 ${isLocked ? 'opacity-30 filter blur-[3px] pointer-events-none' : 'opacity-100'}`} id="answers-block">
                        {keysToRender.map((key, index) => {
                            const value = question.options[key];
                            if (!value || value.trim() === '') return null;

                            const displayValue = sanitizeOptionText(value as string);
                            if (!displayValue) return null;

                            const isEliminated = eliminatedOptions.includes(key);
                            const isSelected = selectedOption === key;
                            const isCorrect = question.correctAnswer === key;
                            const highlights = evidence?.options[key]; 

                            const visualLabel = String.fromCharCode(65 + index); 

                            let btnClass = "w-full text-left p-3.5 rounded-xl border-2 transition-all flex gap-3 items-start group ";

                            if (isEliminated) {
                                btnClass += "bg-slate-900/50 border-transparent opacity-40 grayscale decoration-slate-500 line-through cursor-not-allowed";
                            } else if (isRevealed) {
                                if (isCorrect) {
                                    btnClass += "bg-emerald-500/20 border-emerald-500 text-emerald-100";
                                } else if (isSelected) {
                                    btnClass += "bg-rose-500/20 border-rose-500 text-rose-100";
                                } else {
                                    btnClass += "bg-white/5 border-white/5 opacity-50";
                                }
                            } else {
                                if (isEliminationMode) {
                                    btnClass += "bg-white/5 border-rose-500/30 hover:bg-rose-500/10 hover:border-rose-500 text-slate-300 cursor-crosshair";
                                } else if (isSelected) {
                                    btnClass += "bg-sky-600 border-sky-500 text-white shadow-lg";
                                } else {
                                    btnClass += "bg-white/5 border-white/10 hover:border-sky-500/30 hover:bg-white/10 active:scale-[0.99]";
                                }
                            }

                            return (
                                <button
                                    key={key}
                                    onClick={() => handleOptionClick(key)}
                                    disabled={isRevealed || (isLocked)}
                                    className={btnClass}
                                >
                                    <strong className={`shrink-0 text-base ${!isRevealed && !isSelected && !isEliminated ? 'text-sky-500 group-hover:text-sky-400' : 'text-current'}`}>{visualLabel})</strong>
                                    <span className="leading-snug pt-0.5 text-sm md:text-base w-full">
                                        <PromptText text={displayValue} highlights={highlights} />
                                    </span>
                                    {isRevealed && isCorrect && <CheckCircleIcon className="w-5 h-5 ml-auto shrink-0 text-emerald-400" />}
                                    {isRevealed && isSelected && !isCorrect && <XCircleIcon className="w-5 h-5 ml-auto shrink-0 text-rose-400" />}
                                    {!isRevealed && isEliminated && <TrashIcon className="w-4 h-4 ml-auto shrink-0 text-slate-600" />}
                                </button>
                            );
                        })}
                    </div>
                )}
            </div>

            {isRevealed && (
                <div className="animate-fade-in pt-6 border-t border-white/10">
                   <QuestionExplanationBlocks 
                        question={question} 
                        userAnswer={selectedOption} 
                        showTitle={true}
                   />
                </div>
            )}
        </div>
    );
};

export default QuestionViewer;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Question, TrapscanEntry, TrapscanSessionConfig } from '../types';
import { useSettings } from '../contexts/SettingsContext';
import * as trapscanLogic from '../services/trapscanLogic';
import { 
    XMarkIcon, LockClosedIcon, ArrowRightIcon, 
    ExclamationTriangleIcon, FullScreenIcon, ExitFullScreenIcon
} from './icons';
import QuestionViewer from './QuestionViewer';
import TrapscanGate from './TrapscanGate';
import QuestionActionsMenu, { QuestionContextType } from './QuestionActionsMenu';
import ReadingContainer from './ui/ReadingContainer';
import { getText } from '../utils/i18nText';
import { isStrictQuestion } from '../services/contentGate';
import ConfirmationModal from './ConfirmationModal';
import { useQuestionDispatch } from '../contexts/QuestionContext';
import { sanitizeOptionText } from '../services/questionParser';

interface QuestionRunnerProps {
    question: Question;
    sessionConfig?: TrapscanSessionConfig | null;
    onResult: (rating: 'again' | 'hard' | 'good' | 'easy', timeTaken: number, trapscanData?: TrapscanEntry) => void;
    onNext?: () => void;
    isLast?: boolean;
    onClose?: () => void;
    context: QuestionContextType;
    mode?: 'SRS' | 'SIMPLE';
    allowGaps?: boolean;
    onEdit?: (q: Question) => void;
    onDelete?: (id: string) => void;
}

const MediaBlock: React.FC<{ image?: string, audio?: string }> = ({ image, audio }) => {
    if (!image && !audio) return null;
    return (
        <div className="flex flex-col gap-3 items-center mb-6 w-full animate-fade-in" onClick={e => e.stopPropagation()}>
           {image && (
               <img src={image} alt="Mídia da Questão" className="max-w-full max-h-72 rounded-2xl shadow-2xl object-contain bg-black/20" />
           )}
           {audio && (
               <audio controls src={audio} className="w-full max-w-md h-10 opacity-90 hover:opacity-100 transition-opacity" />
           )}
        </div>
    );
};

// Fisher-Yates Shuffle
function shuffleArray<T>(array: T[]): T[] {
    const arr = [...array];
    for (let i = arr.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [arr[i], arr[j]] = [arr[j], arr[i]];
    }
    return arr;
}

const QuestionRunner: React.FC<QuestionRunnerProps> = ({ 
    question, 
    sessionConfig, 
    onResult, 
    onNext, 
    isLast, 
    onClose, 
    context, 
    mode = 'SRS',
    allowGaps = false,
    onEdit,
    onDelete
}) => {
    const { settings, updateSettings, addXp } = useSettings();
    const { deleteQuestions, registerAttempt } = useQuestionDispatch();
    const scrollRef = useRef<HTMLDivElement>(null);
    const startTimeRef = useRef<number>(Date.now());

    const isInvalidContent = !allowGaps && !isStrictQuestion(question);

    // Shuffle Logic State
    const [orderedKeys, setOrderedKeys] = useState<string[]>([]);

    useEffect(() => {
        if (isInvalidContent) {
            console.warn("[QuestionRunner] Conteúdo inválido detectado. Pulando...", question.id);
            if (onNext) {
                const t = setTimeout(onNext, 100);
                return () => clearTimeout(t);
            }
        }
    }, [question.id, isInvalidContent, onNext]);

    // --- SHUFFLE LOGIC ---
    useEffect(() => {
        if (!question.options) {
             setOrderedKeys([]);
             return;
        }

        // STRICT KEY FILTER: Only allow valid option keys (A-E) AND non-empty content
        const allowedKeys = ['A', 'B', 'C', 'D', 'E'];
        const validKeys = Object.keys(question.options)
            .filter(k => {
                if (!allowedKeys.includes(k)) return false;
                const val = question.options[k];
                // Check if value exists and is not sanitized away
                if (!val || !sanitizeOptionText(val)) return false;
                return true;
            });

        // Check if settings enabled
        if (settings.shuffleAlternatives && !question.isGapType) {
            // DETECT JUDGMENT TYPE TO PREVENT SHUFFLE
            const type = (question.questionType || '').toUpperCase();
            const bank = (question.bank || '').toUpperCase();
            const isJudgement = 
                type.includes('C/E') || 
                type.includes('CERTO') || 
                type.includes('JULGAMENTO') || 
                type.includes('V/F') ||
                bank.includes('CESPE') || 
                bank.includes('CEBRASPE');

            // Also check for explicit C/E keys presence
            const hasExplicitCE = (question.options['C'] === 'Certo' && question.options['E'] === 'Errado');
            const hasImplicitCE = validKeys.length === 2 && 
                Object.values(question.options).some(v => (v as string)?.toUpperCase() === 'CERTO') &&
                Object.values(question.options).some(v => (v as string)?.toUpperCase() === 'ERRADO');

            if (isJudgement || hasExplicitCE || hasImplicitCE) {
                // Keep explicit C/E order if those keys exist
                setOrderedKeys(validKeys.sort()); 
            } else {
                setOrderedKeys(shuffleArray(validKeys));
            }
        } else {
            setOrderedKeys(validKeys.sort()); // Default A-Z
        }
    }, [question.id, settings.shuffleAlternatives, question.options, question.isGapType, question.questionType, question.bank]);

    const [isDeleteConfirmOpen, setIsDeleteConfirmOpen] = useState(false);

    if (isInvalidContent) {
        return (
            <div className="flex flex-col items-center justify-center h-full p-10 text-center space-y-4">
                <ExclamationTriangleIcon className="w-12 h-12 text-amber-500 opacity-50" />
                <h3 className="text-xl font-bold text-white">Conteúdo Incompatível</h3>
                <p className="text-slate-400 text-sm">Este item parece ser uma lacuna em modo questão. Pulando...</p>
                <button onClick={onNext} className="bg-white/10 px-6 py-2 rounded-lg text-sm font-bold uppercase hover:bg-white/20">
                    Forçar Pulo
                </button>
            </div>
        );
    }

    const activeConfig: TrapscanSessionConfig = useMemo(() => {
        if (sessionConfig) return sessionConfig;
        const defaults = { enabled: true, assistMode: true, defaultMode: 'TREINO' as const, lockLevel: 'SOFT' as const };
        return (settings.trapscan as TrapscanSessionConfig) || defaults;
    }, [sessionConfig, settings.trapscan]);

    const [selectedOption, setSelectedOption] = useState<string | null>(null);
    const [isRevealed, setIsRevealed] = useState(false);
    const [trapscanData, setTrapscanData] = useState<TrapscanEntry | undefined>(undefined);
    const [showBlockToast, setShowBlockToast] = useState<string | null>(null);

    const [eliminatedOptions, setEliminatedOptions] = useState<string[]>([]);
    const [isEliminationMode, setIsEliminationMode] = useState(false);
    const [highlightAnchor, setHighlightAnchor] = useState(false);

    useEffect(() => {
        setSelectedOption(null);
        setIsRevealed(false);
        setTrapscanData(undefined);
        setEliminatedOptions([]);
        setIsEliminationMode(false);
        setHighlightAnchor(false);
        setIsDeleteConfirmOpen(false);
        startTimeRef.current = Date.now();

        if (scrollRef.current) {
            scrollRef.current.scrollTo({ top: 0, behavior: 'instant' });
        }
    }, [question.id]);

    const isGap = allowGaps && (question.isGapType || question.questionText.includes('{{'));
    const isLocked = !isGap && trapscanLogic.checkAlternativesLocked(activeConfig, trapscanData);
    const blockReason = !isGap ? trapscanLogic.getSubmitBlockReason(activeConfig, trapscanData, !!selectedOption) : null;
    const canSubmit = !blockReason;

    const handleOptionSelect = (key: string) => {
        if (!isRevealed && !isLocked && !isEliminationMode) {
            setSelectedOption(key);
        }
    };

    const handleEliminate = (key: string) => {
        setEliminatedOptions(prev => {
             if (prev.includes(key)) return prev.filter(k => k !== key);
             return [...prev, key];
        });
    };

    const handleReveal = () => {
        if (!canSubmit) {
            setShowBlockToast(blockReason);
            setTimeout(() => setShowBlockToast(null), 3000);
            return;
        }
        setIsRevealed(true);
    };

    const handleRating = (rating: 'again' | 'hard' | 'good' | 'easy') => {
        const timeTaken = (Date.now() - startTimeRef.current) / 1000;
        // @ts-ignore - Dynamic addition
        const enhancedTrapscanData = { ...trapscanData, orderKeys: orderedKeys };

        onResult(rating, timeTaken, enhancedTrapscanData);
        if (onNext) onNext();
    };

    const handleSimpleNext = () => {
        const isCorrect = selectedOption === question.correctAnswer;
        const timeTaken = (Date.now() - startTimeRef.current) / 1000;
        // @ts-ignore
        const enhancedTrapscanData = { ...trapscanData, orderKeys: orderedKeys };
        onResult(isCorrect ? 'good' : 'again', timeTaken, enhancedTrapscanData);
        if (onNext) onNext();
    };

    const toggleReaderMode = () => {
        const newMode = settings.readerMode === 'compact' ? 'fullscreen' : 'compact';
        updateSettings({ readerMode: newMode });
    };

    const handleDeleteRequest = (id: string) => {
        setIsDeleteConfirmOpen(true);
    };

    const handleConfirmDelete = () => {
        deleteQuestions([question.id]);
        if (onDelete) onDelete(question.id);
        if (onNext) onNext();
        setIsDeleteConfirmOpen(false);
    };

    const showTrapscan = !isGap && trapscanLogic.isTrapscanActive(activeConfig) && !question.isGapType;

    return (
        <div className="flex flex-col h-full bg-[var(--q-surface)] text-[var(--q-text)] relative">
            <header className="px-5 py-4 border-b border-[var(--q-border)] flex justify-between items-center bg-[var(--q-surface)] backdrop-blur-md shrink-0 z-10">
                <div className="min-w-0 pr-4">
                    <h2 className="text-sm font-extrabold tracking-tight truncate uppercase italic">{question.questionRef}</h2>
                    <p className="text-[10px] font-semibold text-[var(--q-muted)] uppercase mt-0.5">{question.subject}</p>
                </div>
                <div className="flex items-center gap-2">
                    {activeConfig?.enabled && showTrapscan && (
                        <div className={`hidden sm:block px-2 py-0.5 rounded text-[9px] font-black uppercase border ${activeConfig.assistMode ? 'bg-indigo-500/10 border-indigo-500/30 text-indigo-400' : 'bg-slate-500/10 border-slate-500/30 text-slate-500'}`}>
                            {activeConfig.assistMode ? (activeConfig.defaultMode === 'GUIA' ? 'GUIA' : `LOCK: ${activeConfig.lockLevel}`) : 'OFF'}
                        </div>
                    )}

                    <button 
                        onClick={toggleReaderMode}
                        className="p-2 rounded-lg text-[var(--q-muted)] hover:bg-[var(--q-hover)] transition-colors hidden sm:block"
                        title={settings.readerMode === 'compact' ? "Expandir Tela" : "Modo Leitura"}
                    >
                        {settings.readerMode === 'compact' ? <FullScreenIcon className="w-5 h-5"/> : <ExitFullScreenIcon className="w-5 h-5"/>}
                    </button>

                    <QuestionActionsMenu 
                        question={question} 
                        context={context} 
                        onEdit={onEdit} 
                        onDelete={handleDeleteRequest} 
                    />

                    {onClose && (
                        <button onClick={onClose} className="p-2 -mr-2 text-[var(--q-muted)] hover:bg-[var(--q-hover)] transition-colors">
                            <XMarkIcon className="w-5 h-5"/>
                        </button>
                    )}
                </div>
            </header>

            <div className="flex-1 overflow-y-auto custom-scrollbar" ref={scrollRef}>
                 <ReadingContainer mode={settings.readerMode} className="py-6 pb-24 md:py-8">
                      <MediaBlock image={question.questionImage} audio={question.questionAudio} />

                      {showTrapscan && !isRevealed && (
                          <TrapscanGate 
                              question={question}
                              isLocked={isLocked}
                              onUnlock={() => {}} 
                              onAllowSubmit={() => {}} 
                              onUpdate={setTrapscanData}
                              userAnswer={selectedOption}
                              configOverride={activeConfig}
                              eliminatedOptions={eliminatedOptions}
                              onSetEliminationMode={setIsEliminationMode}
                              onSetHighlightAnchor={setHighlightAnchor}
                          />
                      )}

                      <QuestionViewer 
                          question={question}
                          selectedOption={selectedOption}
                          isRevealed={isRevealed}
                          onOptionSelect={handleOptionSelect}
                          showMedia={false} 
                          isLocked={isLocked}
                          isEliminationMode={isEliminationMode}
                          eliminatedOptions={eliminatedOptions}
                          onEliminate={handleEliminate}
                          highlightText={highlightAnchor ? getText(question.anchorText) : undefined}
                          orderedKeys={orderedKeys.length > 0 ? orderedKeys : undefined} // Pass shuffled order
                      />
                  </ReadingContainer>
            </div>

            {showBlockToast && (
                <div className="absolute bottom-24 left-1/2 -translate-x-1/2 bg-rose-500 text-white px-6 py-3 rounded-full shadow-2xl font-bold text-xs uppercase tracking-widest z-50 animate-bounce-subtle flex items-center gap-2">
                    <LockClosedIcon className="w-4 h-4" />
                    {showBlockToast}
                </div>
            )}

            {selectedOption && (
                <footer className="p-5 bg-[var(--q-surface)] border-t border-[var(--q-border)] shrink-0 z-20 pb-[calc(1.5rem+env(safe-area-inset-bottom))] shadow-[0_-10px_40px_rgba(0,0,0,0.3)]">
                    <ReadingContainer mode={settings.readerMode} className="!px-0">
                        {!isRevealed ? (
                            <button 
                                onClick={handleReveal} 
                                disabled={!canSubmit && activeConfig?.assistMode && activeConfig?.defaultMode === 'TREINO'}
                                className={`w-full font-black py-4 rounded-2xl shadow-xl transition-all uppercase tracking-widest text-sm flex items-center justify-center gap-2
                                    ${canSubmit || !activeConfig?.assistMode || activeConfig?.defaultMode === 'GUIA'
                                        ? 'bg-sky-600 text-white hover:bg-sky-500 active:scale-[0.98]' 
                                        : 'bg-slate-700 text-slate-500 cursor-not-allowed opacity-80'}`}
                            >
                                {(canSubmit || !activeConfig?.assistMode || activeConfig?.defaultMode === 'GUIA') ? 'Ver Gabarito' : <><LockClosedIcon className="w-4 h-4"/> Complete o Trapscan</>}
                            </button>
                        ) : (
                            mode === 'SRS' ? (
                                <div className="grid grid-cols-4 gap-3 h-20">
                                    <button onClick={() => handleRating('again')} className="rounded-2xl bg-rose-500/10 border-2 border-rose-500/50 text-rose-500 hover:bg-rose-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Errei</span>
                                    </button>
                                    <button onClick={() => handleRating('hard')} className="rounded-2xl bg-amber-500/10 border-2 border-amber-500/50 text-amber-500 hover:bg-amber-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Difícil</span>
                                    </button>
                                    <button onClick={() => handleRating('good')} className="rounded-2xl bg-sky-500/10 border-2 border-sky-500/50 text-sky-500 hover:bg-sky-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
